INSERT INTO `ext_schema` VALUES (3, 1001, '国家', '用于表示国家或地区实体，可关联所属城市、人物国籍等地理与身份信息。', '#FD0E02', 1, 0, '小桐', 1, '2026-04-20 09:32:55', '小桐', 1, '2026-05-15 14:46:47', NULL);
INSERT INTO `ext_schema` VALUES (4, 1001, '城市', '用于表示城市实体，可关联所属国家、企业所在地等空间位置信息。', '#FDB202', 1, 0, '小桐', 1, '2026-04-20 09:32:55', '小桐', 1, '2026-05-15 14:46:58', NULL);
INSERT INTO `ext_schema` VALUES (5, 1001, '企业', '用于表示企业、机构或组织主体，可关联所在城市、所属用户及业务相关信息。', '#FF0FDF', 1, 0, '小桐', 1, '2026-04-20 09:32:55', '小桐', 1, '2026-05-15 14:47:12', NULL);
INSERT INTO `ext_schema` VALUES (7, 1001, '用户', '用于表示平台用户或业务用户主体，可关联其管理的企业、权限或操作数据。', '#0026FF', 1, 0, '小桐', 1, '2026-04-20 09:32:55', '小桐', 1, '2026-05-15 14:47:27', NULL);
INSERT INTO `ext_schema` VALUES (8, 1001, '角色', '用于表示人物在特定场景中的身份、职位或作品角色，可与人物主体建立归属关系。', '#33FF00', 1, 0, '小桐', 1, '2026-04-20 09:32:55', '小桐', 1, '2026-05-15 14:47:42', NULL);
INSERT INTO `ext_schema` VALUES (9, 1001, '器械', '用于表示设备、工具或器械实体，可关联其材料、功能和所属器械类别。', '#FFD000', 1, 0, '小桐', 1, '2026-05-08 16:59:49', '小桐', 1, '2026-05-15 14:47:59', NULL);
INSERT INTO `ext_schema` VALUES (10, 1001, '材料', '用于表示器械制造、组成或使用过程中涉及的材料实体。', '#00FF1E', 1, 0, '小桐', 1, '2026-05-08 16:59:59', '小桐', 1, '2026-05-15 14:48:09', NULL);
INSERT INTO `ext_schema` VALUES (11, 1001, '功能', '用于表示器械具备或实现的能力、用途和作用，可关联相关器械。', '#002FFF', 1, 0, '小桐', 1, '2026-05-08 17:00:09', '小桐', 1, '2026-05-15 14:48:20', NULL);
INSERT INTO `ext_schema` VALUES (12, 1001, '器械类别', '器械类别        用于表示器械的分类类型，可对不同器械进行归类管理，便于按类别检索、统计和维护。', '#FF007B', 1, 0, '小桐', 1, '2026-05-08 17:00:18', '小桐', 1, '2026-05-15 14:49:28', NULL);
