INSERT INTO `ext_unstruct_task_relation` VALUES (47, 1001, 20, 2, 1, 0, '小桐', 1, '2026-05-15 15:49:59', '小桐', NULL, '2026-05-15 15:49:59', NULL);
INSERT INTO `ext_unstruct_task_relation` VALUES (48, 1001, 21, 3, 1, 0, '小桐', 1, '2026-05-15 15:50:27', '小桐', NULL, '2026-05-15 15:50:27', NULL);
INSERT INTO `ext_unstruct_task_relation` VALUES (49, 1001, 22, 5, 1, 0, '小桐', 1, '2026-05-15 15:50:52', '小桐', NULL, '2026-05-15 15:50:52', NULL);
INSERT INTO `ext_unstruct_task_relation` VALUES (50, 1001, 23, 5, 1, 0, '小桐', 1, '2026-05-15 15:51:21', '小桐', NULL, '2026-05-15 15:51:21', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (1, 1001, 1, 1, 1, '歌手周杰伦创作了多首经典歌曲，如《稻香》，这首歌深受中国各地听众的喜爱。', 0, 0, '小桐', NULL, '2026-04-20 09:32:55', '小桐', 1, '2026-04-20 09:32:55', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (2, 1001, 1, 1, 2, '在北京举办的华语乐坛盛事——第30届金曲奖颁奖典礼上，歌手邓紫棋凭借其歌曲《句号》获得了最佳女歌手奖。', 0, 0, '小桐', NULL, '2026-04-20 09:32:55', '小桐', 1, '2026-04-20 09:32:55', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (3, 1001, 1, 1, 3, '上海是中国电影产业的重要基地之一，这里诞生了许多优秀的作品，比如由导演徐峥执导的电影《我不是药神》。', 0, 0, '小桐', NULL, '2026-04-20 09:32:55', '小桐', 1, '2026-04-20 09:32:55', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (4, 1001, 2, 2, 1, '斯坦福大学位于美国加利福尼亚州硅谷，是一所世界领先的学府，培养了包括埃隆·马斯克在内的多位科技界领军人物。', 0, 0, '小桐', NULL, '2026-04-20 09:32:55', '小桐', 1, '2026-04-20 09:32:55', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (5, 1001, 2, 2, 2, '谷歌DeepMind总部设在旧金山湾区，该公司由英国伦敦的研究团队创建，并因开发出击败围棋冠军的AI程序《AlphaGo》而闻名。', 0, 0, '小桐', NULL, '2026-04-20 09:32:55', '小桐', 1, '2026-04-20 09:32:55', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (6, 1001, 2, 2, 3, '演员兼程序员梅丽莎·劳奇毕业于加州大学洛杉矶分校（UCLA），她曾在电视剧《生活大爆炸》中饰演科学家角色。', 0, 0, '小桐', NULL, '2026-04-20 09:32:55', '小桐', 1, '2026-04-20 09:32:55', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (7, 1001, 2, 2, 4, '东京属于温带季风气候，同时也孕育了许多面向全球市场的人工智能初创公司，如总部位于该市的Preferred Networks。', 0, 0, '小桐', NULL, '2026-04-20 09:32:55', '小桐', 1, '2026-04-20 09:32:55', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (8, 1001, 2, 2, 5, '日本歌手椎名林檎创作的歌曲《歌舞伎町女王》流行于东京都，同时她也为一部讲述人工智能伦理问题的日本电视综艺《未来人类》演唱过主题曲。', 0, 0, '小桐', NULL, '2026-04-20 09:32:55', '小桐', 1, '2026-04-20 09:32:55', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (9, 1001, 2, 2, 6, '中国杭州是互联网企业阿里巴巴集团的所在地，这座城市还以全年温和湿润的亚热带季风气候著称。', 0, 0, '小桐', NULL, '2025-05-27 13:35:02', '小桐', 1, '2026-04-20 09:32:55', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (10, 1001, 2, 2, 10, '加拿大歌手格莱姆斯曾发布歌曲《We Appreciate Power》，探讨人工智能对社会的影响，并与埃隆·马斯克共同关注脑机接口技术的发展。', 0, 0, '小桐', NULL, '2026-04-20 09:32:55', '小桐', 1, '2026-04-20 09:32:55', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (268, 1001, 9, 7, 1, '可控塑形：导管的远端（前端）可以被塑造成特定的弯度，以适应不同解剖结构的需求。这种塑形通常是通过内部的金属丝（称为“J形导丝”）来实现的。', 1, 0, '小桐', NULL, '2026-05-09 10:01:13', '小桐', NULL, '2026-05-09 10:01:13', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (269, 1001, 9, 7, 2, '第二代支架：为可降解支架，如聚乳酸（PLA）支架。其最大的特点是可在植入后数月到数年内逐渐降解并被人体吸收，最终血管可以恢复自然状态。', 1, 0, '小桐', NULL, '2026-05-09 10:01:13', '小桐', NULL, '2026-05-09 10:01:13', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (270, 1001, 9, 7, 3, '导管的主体材料多为高分子聚合物，如聚氨酯或聚乙烯，这些材料兼具柔韧性和足够的支撑力。', 1, 0, '小桐', NULL, '2026-05-09 10:01:13', '小桐', NULL, '2026-05-09 10:01:13', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (271, 1001, 9, 7, 4, '其原理是将一个折叠在导管尖端的微型球囊送至血管狭窄处，然后注入液体将其膨胀，从而撑开狭窄的血管，恢复血流。', 1, 0, '小桐', NULL, '2026-05-09 10:01:13', '小桐', NULL, '2026-05-09 10:01:13', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (272, 1001, 9, 7, 5, '导丝是介入治疗的“先锋”，负责在血管内开辟通路，引导其他器械到达目的地。', 1, 0, '小桐', NULL, '2026-05-09 10:01:13', '小桐', NULL, '2026-05-09 10:01:13', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (273, 1001, 9, 7, 6, '导管是介入治疗的“通道”，负责将各种器械和药物精准送达心脏或血管的病变部位。', 1, 0, '小桐', NULL, '2026-05-09 10:01:13', '小桐', NULL, '2026-05-09 10:01:13', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (274, 1001, 9, 7, 7, '超滑涂层：导管表面通常涂有聚四氟乙烯（PTFE）等材料，极大地降低了与血管壁的摩擦力，使得导管能够轻松通过狭窄或迂曲的血管。', 1, 0, '小桐', NULL, '2026-05-09 10:01:13', '小桐', NULL, '2026-05-09 10:01:13', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (275, 1001, 9, 7, 8, '支架是介入治疗中最关键的器械，它的作用是在球囊扩张后，为血管提供一个永久的支撑，防止血管回缩或再狭窄。', 1, 0, '小桐', NULL, '2026-05-09 10:01:13', '小桐', NULL, '2026-05-09 10:01:13', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (276, 1001, 9, 7, 9, '球囊导管是经皮冠状动脉介入治疗（PCI）中最基础的器械之一。', 1, 0, '小桐', NULL, '2026-05-09 10:01:13', '小桐', NULL, '2026-05-09 10:01:13', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (277, 1001, 9, 7, 10, '第一代支架：主要为不锈钢支架，优点是强度高，但缺点是永久存留体内，可能引起晚期血栓或限制血管的自然舒缩。', 1, 0, '小桐', NULL, '2026-05-09 10:01:13', '小桐', NULL, '2026-05-09 10:01:13', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (278, 1001, 9, 7, 11, '现代球囊要求具备高爆破压力（以确保安全）、良好的顺应性（即扩张时能均匀受力）以及快速充盈和排空的能力。', 1, 0, '小桐', NULL, '2026-05-09 10:01:13', '小桐', NULL, '2026-05-09 10:01:13', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (279, 1001, 9, 7, 12, '造影剂是介入治疗的“眼睛”。通过向血管内注射含碘的造影剂，可以使血管在X线下显影，从而让医生清晰地看到血管的形态、狭窄的位置和程度。', 1, 0, '小桐', NULL, '2026-05-09 10:01:13', '小桐', NULL, '2026-05-09 10:01:13', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (280, 1001, 9, 7, 13, '导管表面通常涂有聚四氟乙烯（PTFE）等材料，极大地降低了与血管壁的摩擦力，使得导管能够轻松通过狭窄或迂曲的血管。', 1, 0, '小桐', NULL, '2026-05-09 10:01:13', '小桐', NULL, '2026-05-09 10:01:13', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (281, 1001, 9, 7, 14, '现代球囊要求具备高爆破压力（以确保安全）、良好的顺应性（即扩张时能均匀受力）以及快速充盈和排空的能力。', 1, 0, '小桐', NULL, '2026-05-09 10:01:13', '小桐', NULL, '2026-05-09 10:01:13', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (282, 1001, 9, 7, 15, '第三代支架：为药物洗脱支架（DES），在金属支架表面涂有可缓慢释放的抗增殖药物（如雷帕霉素）。这种支架既能提供永久支撑，又能抑制血管内膜的过度增生，从而显著降低再狭窄率。', 1, 0, '小桐', NULL, '2026-05-09 10:01:13', '小桐', NULL, '2026-05-09 10:01:13', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (283, 1001, 9, 7, 1, '可控塑形：导管的远端（前端）可以被塑造成特定的弯度，以适应不同解剖结构的需求。这种塑形通常是通过内部的金属丝（称为“J形导丝”）来实现的。', 1, 0, '小桐', NULL, '2026-05-09 10:16:22', '小桐', NULL, '2026-05-09 10:16:22', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (284, 1001, 9, 7, 2, '球囊导管是经皮冠状动脉介入治疗（PCI）中最基础的器械之一。', 1, 0, '小桐', NULL, '2026-05-09 10:16:22', '小桐', NULL, '2026-05-09 10:16:22', NULL);
