INSERT INTO `ext_unstruct_task_text` VALUES (304, 1001, 9, 7, 12, '导管表面通常涂有聚四氟乙烯（PTFE）等材料，极大地降低了与血管壁的摩擦力，使得导管能够轻松通过狭窄或迂曲的血管。', 1, 0, '小桐', NULL, '2026-05-09 11:15:14', '小桐', NULL, '2026-05-09 11:15:14', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (305, 1001, 9, 7, 13, '第三代支架：为药物洗脱支架（DES），在金属支架表面涂有可缓慢释放的抗增殖药物（如雷帕霉素）。这种支架既能提供永久支撑，又能抑制血管内膜的过度增生，从而显著降低再狭窄率。', 1, 0, '小桐', NULL, '2026-05-09 11:15:14', '小桐', NULL, '2026-05-09 11:15:14', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (306, 1001, 9, 7, 1, '可控塑形：导管的远端（前端）可以被塑造成特定的弯度，以适应不同解剖结构的需求。这种塑形通常是通过内部的金属丝（称为“J形导丝”）来实现的。', 1, 0, '小桐', NULL, '2026-05-09 11:24:57', '小桐', NULL, '2026-05-09 11:24:57', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (307, 1001, 9, 7, 2, '球囊导管是经皮冠状动脉介入治疗（PCI）中最基础的器械之一。其原理是将一个折叠在导管尖端的微型球囊送至血管狭窄处，然后注入液体将其膨胀，从而撑开狭窄的血管，恢复血流。', 1, 0, '小桐', NULL, '2026-05-09 11:24:57', '小桐', NULL, '2026-05-09 11:24:57', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (308, 1001, 9, 7, 3, '第一代支架：主要为不锈钢支架，优点是强度高，但缺点是永久存留体内，可能引起晚期血栓或限制血管的自然舒缩。', 1, 0, '小桐', NULL, '2026-05-09 11:24:57', '小桐', NULL, '2026-05-09 11:24:57', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (309, 1001, 9, 7, 4, '造影剂是介入治疗的“眼睛”。通过向血管内注射含碘的造影剂，可以使血管在X线下显影，从而让医生清晰地看到血管的形态、狭窄的位置和程度。', 1, 0, '小桐', NULL, '2026-05-09 11:24:57', '小桐', NULL, '2026-05-09 11:24:57', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (310, 1001, 9, 7, 5, '导丝是介入治疗的“先锋”，负责在血管内开辟通路，引导其他器械到达目的地。现代导丝的尖端非常柔软，可以安全地通过极其复杂的病变，而其尾部则非常坚硬，以保证操作者能够精确地控制其走向。', 1, 0, '小桐', NULL, '2026-05-09 11:24:57', '小桐', NULL, '2026-05-09 11:24:57', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (311, 1001, 9, 7, 6, '导管是介入治疗的“通道”，负责将各种器械和药物精准送达心脏或血管的病变部位。', 1, 0, '小桐', NULL, '2026-05-09 11:24:57', '小桐', NULL, '2026-05-09 11:24:57', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (312, 1001, 9, 7, 7, '超滑涂层：导管表面通常涂有聚四氟乙烯（PTFE）等材料，极大地降低了与血管壁的摩擦力，使得导管能够轻松通过狭窄或迂曲的血管。', 1, 0, '小桐', NULL, '2026-05-09 11:24:57', '小桐', NULL, '2026-05-09 11:24:57', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (313, 1001, 9, 7, 8, '第二代支架：为可降解支架，如聚乳酸（PLA）支架。其最大的特点是可在植入后数月到数年内逐渐降解并被人体吸收，最终血管可以恢复自然状态。', 1, 0, '小桐', NULL, '2026-05-09 11:24:57', '小桐', NULL, '2026-05-09 11:24:57', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (314, 1001, 9, 7, 9, '支架是介入治疗中最关键的器械，它的作用是在球囊扩张后，为血管提供一个永久的支撑，防止血管回缩或再狭窄。', 1, 0, '小桐', NULL, '2026-05-09 11:24:57', '小桐', NULL, '2026-05-09 11:24:57', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (315, 1001, 9, 7, 10, '第三代支架：为药物洗脱支架（DES），在金属支架表面涂有可缓慢释放的抗增殖药物（如雷帕霉素）。这种支架既能提供永久支撑，又能抑制血管内膜的过度增生，从而显著降低再狭窄率。', 1, 0, '小桐', NULL, '2026-05-09 11:24:57', '小桐', NULL, '2026-05-09 11:24:57', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (316, 1001, 9, 7, 1, '可控塑形：导管的远端（前端）可以被塑造成特定的弯度，以适应不同解剖结构的需求。这种塑形通常是通过内部的金属丝（称为“J形导丝”）来实现的。', 1, 0, '小桐', NULL, '2026-05-09 11:46:09', '小桐', NULL, '2026-05-09 11:46:09', NULL);
