INSERT INTO `ext_unstruct_task_text` VALUES (331, 1001, 9, 7, 6, '超滑涂层：导管表面通常涂有聚四氟乙烯（PTFE）等材料，极大地降低了与血管壁的摩擦力，使得导管能够轻松通过狭窄或迂曲的血管。', 1, 0, '小桐', NULL, '2026-05-09 11:57:48', '小桐', NULL, '2026-05-09 11:57:48', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (332, 1001, 9, 7, 7, '导管的主体材料多为高分子聚合物，如聚氨酯或聚乙烯，这些材料兼具柔韧性和足够的支撑力。', 1, 0, '小桐', NULL, '2026-05-09 11:57:48', '小桐', NULL, '2026-05-09 11:57:48', NULL);
