INSERT INTO `ext_unstruct_task_text` VALUES (336, 1001, 9, 7, 11, '第一代支架：主要为不锈钢支架，优点是强度高，但缺点是永久存留体内，可能引起晚期血栓或限制血管的自然舒缩。', 1, 0, '小桐', NULL, '2026-05-09 11:57:48', '小桐', NULL, '2026-05-09 11:57:48', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (337, 1001, 9, 7, 12, '球囊材料经历了从早期的天然乳胶到现在的高分子材料（如聚酰胺、聚乙烯等）的演变。现代球囊要求具备高爆破压力（以确保安全）、良好的顺应性（即扩张时能均匀受力）以及快速充盈和排空的能力。', 1, 0, '小桐', NULL, '2026-05-09 11:57:48', '小桐', NULL, '2026-05-09 11:57:48', NULL);
INSERT INTO `ext_unstruct_task_text` VALUES (338, 1001, 9, 7, 13, '造影剂是介入治疗的“眼睛”。通过向血管内注射含碘的造影剂，可以使血管在X线下显影，从而让医生清晰地看到血管的形态、狭窄的位置和程度。', 1, 0, '小桐', NULL, '2026-05-09 11:57:48', '小桐', NULL, '2026-05-09 11:57:48', NULL);
