INSERT INTO `ext_unstruct_task_text` VALUES (340, 1001, 9, 7, 15, '导管的主体材料多为高分子聚合物，如聚氨酯或聚乙烯，这些材料兼具柔韧性和足够的支撑力。', 1, 0, '小桐', NULL, '2026-05-09 11:57:48', '小桐', NULL, '2026-05-09 11:57:48', NULL);
