INSERT INTO `ext_unstruct_task_text` VALUES (352, 1001, 9, 7, 12, '造影剂是介入治疗的“眼睛”。通过向血管内注射含碘的造影剂，可以使血管在X线下显影，从而让医生清晰地看到血管的形态、狭窄的位置和程度。', 1, 0, '小桐', NULL, '2026-05-09 13:34:10', '小桐', NULL, '2026-05-09 13:34:10', NULL);
