INSERT INTO `kb_runtime_node` VALUES (13, 1001, 7, '1', 1, 1, '{\"context\":\"心血管介入治疗器械：从导管到支架的全链条技术解析心血管介入治疗是现代心脏病学的核心技术之一，其成功的关键在于精密的器械。这些器械不仅是手术的工具，更是材料科学与生物医学工程的结晶。本文将深入探讨介入治疗中核心器械的技术原理与材料选择。一、导管系统：介入治疗的“导航车”\\n技术原理：导管是介入治疗的“通道”，负责将各种器械和药物精准送达心脏或血管的病变部位\\n。其核心技术在于“超滑”涂层和“可控塑形”。\\n超滑涂层：导管表面通常涂有聚四氟乙烯（PTFE）等材料，极大地降低了与血管壁的摩擦力，使得导管能够轻松通过狭窄或迂曲的血管。\\n可控塑形：导管的远端（前端）可以被塑造成特定的弯度，以适应不同解剖结构的需求。这种塑形通常是通过内部的金属丝（称为“J形导丝”）来实现的。\\n材料科学：导管的主体材料多为高分子聚合物，如聚氨酯或聚乙烯，这些材料兼具柔韧性和足够的支撑力。\\n二、球囊扩张导管：撑开血管的“微型气球”\\n技术原理：球囊导管是经皮冠状动脉介入治疗（PCI）中最基础的器械之一\\n。其原理是将一个折叠在导管尖端的微型球囊送至血管狭窄处，然后注入液体将其膨胀，从而撑开狭窄的血管，恢复血流。\\n材料科学：球囊材料经历了从早期的天然乳胶到现在的高分子材料（如聚酰胺、聚乙烯等）的演变。现代球囊要求具备高爆破压力（以确保安全）、良好的顺应性（即扩张时能均匀受力）以及快速充盈和排空的能力。\\n三、冠状动脉支架：血管的“永久性骨架”\\n技术原理：支架是介入治疗中最关键的器械，它的作用是在球囊扩张后，为血管提供一个永久的支撑，防止血管回缩或再狭窄\\n。\\n材料科学：支架材料的选择是其技术发展的核心。\\n第一代支架：主要为不锈钢支架，优点是强度高，但缺点是永久存留体内，可能引起晚期血栓或限制血管的自然舒缩。\\n第二代支架：为可降解支架，如聚乳酸（PLA）支架。其最大的特点是可在植入后数月到数年内逐渐降解并被人体吸收，最终血管可以恢复自然状态。\\n第三代支架：为药物洗脱支架（DES），在金属支架表面涂有可缓慢释放的抗增殖药物（如雷帕霉素）。这种支架既能提供永久支撑，又能抑制血管内膜的过度增生，从而显著降低再狭窄率。\\n四、辅助器械：介入治疗的“得力助手”\\n导丝：导丝是介入治疗的“先锋”，负责在血管内开辟通路，引导其他器械到达目的地。现代导丝的尖端非常柔软，可以安全地通过极其复杂的病变，而其尾部则非常坚硬，以保证操作者能够精确地控制其走向。\\n造影剂：造影剂是介入治疗的“眼睛”。通过向血管内注射含碘的造影剂，可以使血管在X线下显影，从而让医生清晰地看到血管的形态、狭窄的位置和程度。\\n\",\"entityCallWord\":\"器械、功能、材料、器械类别\",\"relationCallWord\":\"使用、具有、属于\"}', '{\"1.context\":\"心血管介入治疗器械：从导管到支架的全链条技术解析心血管介入治疗是现代心脏病学的核心技术之一，其成功的关键在于精密的器械。这些器械不仅是手术的工具，更是材料科学与生物医学工程的结晶。本文将深入探讨介入治疗中核心器械的技术原理与材料选择。一、导管系统：介入治疗的“导航车”\\n技术原理：导管是介入治疗的“通道”，负责将各种器械和药物精准送达心脏或血管的病变部位\\n。其核心技术在于“超滑”涂层和“可控塑形”。\\n超滑涂层：导管表面通常涂有聚四氟乙烯（PTFE）等材料，极大地降低了与血管壁的摩擦力，使得导管能够轻松通过狭窄或迂曲的血管。\\n可控塑形：导管的远端（前端）可以被塑造成特定的弯度，以适应不同解剖结构的需求。这种塑形通常是通过内部的金属丝（称为“J形导丝”）来实现的。\\n材料科学：导管的主体材料多为高分子聚合物，如聚氨酯或聚乙烯，这些材料兼具柔韧性和足够的支撑力。\\n二、球囊扩张导管：撑开血管的“微型气球”\\n技术原理：球囊导管是经皮冠状动脉介入治疗（PCI）中最基础的器械之一\\n。其原理是将一个折叠在导管尖端的微型球囊送至血管狭窄处，然后注入液体将其膨胀，从而撑开狭窄的血管，恢复血流。\\n材料科学：球囊材料经历了从早期的天然乳胶到现在的高分子材料（如聚酰胺、聚乙烯等）的演变。现代球囊要求具备高爆破压力（以确保安全）、良好的顺应性（即扩张时能均匀受力）以及快速充盈和排空的能力。\\n三、冠状动脉支架：血管的“永久性骨架”\\n技术原理：支架是介入治疗中最关键的器械，它的作用是在球囊扩张后，为血管提供一个永久的支撑，防止血管回缩或再狭窄\\n。\\n材料科学：支架材料的选择是其技术发展的核心。\\n第一代支架：主要为不锈钢支架，优点是强度高，但缺点是永久存留体内，可能引起晚期血栓或限制血管的自然舒缩。\\n第二代支架：为可降解支架，如聚乳酸（PLA）支架。其最大的特点是可在植入后数月到数年内逐渐降解并被人体吸收，最终血管可以恢复自然状态。\\n第三代支架：为药物洗脱支架（DES），在金属支架表面涂有可缓慢释放的抗增殖药物（如雷帕霉素）。这种支架既能提供永久支撑，又能抑制血管内膜的过度增生，从而显著降低再狭窄率。\\n四、辅助器械：介入治疗的“得力助手”\\n导丝：导丝是介入治疗的“先锋”，负责在血管内开辟通路，引导其他器械到达目的地。现代导丝的尖端非常柔软，可以安全地通过极其复杂的病变，而其尾部则非常坚硬，以保证操作者能够精确地控制其走向。\\n造影剂：造影剂是介入治疗的“眼睛”。通过向血管内注射含碘的造影剂，可以使血管在X线下显影，从而让医生清晰地看到血管的形态、狭窄的位置和程度。\\n\",\"node_1.relationCallWord\":\"使用、具有、属于\",\"node_1.context\":\"心血管介入治疗器械：从导管到支架的全链条技术解析心血管介入治疗是现代心脏病学的核心技术之一，其成功的关键在于精密的器械。这些器械不仅是手术的工具，更是材料科学与生物医学工程的结晶。本文将深入探讨介入治疗中核心器械的技术原理与材料选择。一、导管系统：介入治疗的“导航车”\\n技术原理：导管是介入治疗的“通道”，负责将各种器械和药物精准送达心脏或血管的病变部位\\n。其核心技术在于“超滑”涂层和“可控塑形”。\\n超滑涂层：导管表面通常涂有聚四氟乙烯（PTFE）等材料，极大地降低了与血管壁的摩擦力，使得导管能够轻松通过狭窄或迂曲的血管。\\n可控塑形：导管的远端（前端）可以被塑造成特定的弯度，以适应不同解剖结构的需求。这种塑形通常是通过内部的金属丝（称为“J形导丝”）来实现的。\\n材料科学：导管的主体材料多为高分子聚合物，如聚氨酯或聚乙烯，这些材料兼具柔韧性和足够的支撑力。\\n二、球囊扩张导管：撑开血管的“微型气球”\\n技术原理：球囊导管是经皮冠状动脉介入治疗（PCI）中最基础的器械之一\\n。其原理是将一个折叠在导管尖端的微型球囊送至血管狭窄处，然后注入液体将其膨胀，从而撑开狭窄的血管，恢复血流。\\n材料科学：球囊材料经历了从早期的天然乳胶到现在的高分子材料（如聚酰胺、聚乙烯等）的演变。现代球囊要求具备高爆破压力（以确保安全）、良好的顺应性（即扩张时能均匀受力）以及快速充盈和排空的能力。\\n三、冠状动脉支架：血管的“永久性骨架”\\n技术原理：支架是介入治疗中最关键的器械，它的作用是在球囊扩张后，为血管提供一个永久的支撑，防止血管回缩或再狭窄\\n。\\n材料科学：支架材料的选择是其技术发展的核心。\\n第一代支架：主要为不锈钢支架，优点是强度高，但缺点是永久存留体内，可能引起晚期血栓或限制血管的自然舒缩。\\n第二代支架：为可降解支架，如聚乳酸（PLA）支架。其最大的特点是可在植入后数月到数年内逐渐降解并被人体吸收，最终血管可以恢复自然状态。\\n第三代支架：为药物洗脱支架（DES），在金属支架表面涂有可缓慢释放的抗增殖药物（如雷帕霉素）。这种支架既能提供永久支撑，又能抑制血管内膜的过度增生，从而显著降低再狭窄率。\\n四、辅助器械：介入治疗的“得力助手”\\n导丝：导丝是介入治疗的“先锋”，负责在血管内开辟通路，引导其他器械到达目的地。现代导丝的尖端非常柔软，可以安全地通过极其复杂的病变，而其尾部则非常坚硬，以保证操作者能够精确地控制其走向。\\n造影剂：造影剂是介入治疗的“眼睛”。通过向血管内注射含碘的造影剂，可以使血管在X线下显影，从而让医生清晰地看到血管的形态、狭窄的位置和程度。\\n\",\"node_1.entityCallWord\":\"器械、功能、材料、器械类别\",\"1.entityCallWord\":\"器械、功能、材料、器械类别\",\"1.relationCallWord\":\"使用、具有、属于\"}', 1, 0, NULL, NULL, '2026-05-08 17:22:23', NULL, NULL, '2026-05-08 17:22:23', NULL);
INSERT INTO `kb_runtime_node` VALUES (14, 1001, 7, 'llm-1774493047231', 2, 1, '{}', '{\"llm-1774493047231.text\":\"```json\\n{\\n    \\\"entities\\\": [\\n        {\\n            \\\"实体文本\\\": \\\"导管\\\",\\n            \\\"实体类型\\\": \\\"器械\\\",\\n            \\\"片段\\\": \\\"导管是介入治疗的“通道”，负责将各种器械和药物精准送达心脏或血管的病变部位。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"超滑涂层\\\",\\n            \\\"实体类型\\\": \\\"功能\\\",\\n            \\\"片段\\\": \\\"超滑涂层：导管表面通常涂有聚四氟乙烯（PTFE）等材料，极大地降低了与血管壁的摩擦力，使得导管能够轻松通过狭窄或迂曲的血管。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"可控塑形\\\",\\n            \\\"实体类型\\\": \\\"功能\\\",\\n            \\\"片段\\\": \\\"可控塑形：导管的远端（前端）可以被塑造成特定的弯度，以适应不同解剖结构的需求。这种塑形通常是通过内部的金属丝（称为“J形导丝”）来实现的。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"聚四氟乙烯（PTFE）\\\",\\n            \\\"实体类型\\\": \\\"材料\\\",\\n            \\\"片段\\\": \\\"导管表面通常涂有聚四氟乙烯（PTFE）等材料，极大地降低了与血管壁的摩擦力，使得导管能够轻松通过狭窄或迂曲的血管。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"球囊扩张导管\\\",\\n            \\\"实体类型\\\": \\\"器械\\\",\\n            \\\"片段\\\": \\\"球囊导管是经皮冠状动脉介入治疗（PCI）中最基础的器械之一。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"球囊\\\",\\n            \\\"实体类型\\\": \\\"功能\\\",\\n            \\\"片段\\\": \\\"其原理是将一个折叠在导管尖端的微型球囊送至血管狭窄处，然后注入液体将其膨胀，从而撑开狭窄的血管，恢复血流。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"聚酰胺\\\",\\n            \\\"实体类型\\\": \\\"材料\\\",\\n            \\\"片段\\\": \\\"球囊材料经历了从早期的天然乳胶到现在的高分子材料（如聚酰胺、聚乙烯等）的演变。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"聚乙烯\\\",\\n            \\\"实体类型\\\": \\\"材料\\\",\\n            \\\"片段\\\": \\\"球囊材料经历了从早期的天然乳胶到现在的高分子材料（如聚酰胺、聚乙烯等）的演变。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"冠状动脉支架\\\",\\n            \\\"实体类型\\\": \\\"器械\\\",\\n            \\\"片段\\\": \\\"支架是介入治疗中最关键的器械，它的作用是在球囊扩张后，为血管提供一个永久的支撑，防止血管回缩或再狭窄。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"不锈钢支架\\\",\\n            \\\"实体类型\\\": \\\"材料\\\",\\n            \\\"片段\\\": \\\"第一代支架：主要为不锈钢支架，优点是强度高，但缺点是永久存留体内，可能引起晚期血栓或限制血管的自然舒缩。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"聚乳酸（PLA）支架\\\",\\n            \\\"实体类型\\\": \\\"材料\\\",\\n            \\\"片段\\\": \\\"第二代支架：为可降解支架，如聚乳酸（PLA）支架。其最大的特点是可在植入后数月到数年内逐渐降解并被人体吸收，最终血管可以恢复自然状态。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"药物洗脱支架（DES）\\\",\\n            \\\"实体类型\\\": \\\"器械\\\",\\n            \\\"片段\\\": \\\"第三代支架：为药物洗脱支架（DES），在金属支架表面涂有可缓慢释放的抗增殖药物（如雷帕霉素）。这种支架既能提供永久支撑，又能抑制血管内膜的过度增生，从而显著降低再狭窄率。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"导丝\\\",\\n            \\\"实体类型\\\": \\\"器械\\\",\\n            \\\"片段\\\": \\\"导丝是介入治疗的“先锋”，负责在血管内开辟通路，引导其他器械到达目的地。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"造影剂\\\",\\n            \\\"实体类型\\\": \\\"器械\\\",\\n            \\\"片段\\\": \\\"造影剂是介入治疗的“眼睛”。通过向血管内注射含碘的造影剂，可以使血管在X线下显影，从而让医生清晰地看到血管的形态、狭窄的位置和程度。\\\",\\n            \\\"属性\\\": {}\\n        }\\n    ],\\n    \\\"relations\\\": [\\n        {\\n            \\\"头实体\\\": \\\"导管\\\",\\n            \\\"关系\\\": \\\"具有\\\",\\n            \\\"尾实体\\\": \\\"超滑涂层\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"导管\\\",\\n            \\\"关系\\\": \\\"具有\\\",\\n            \\\"尾实体\\\": \\\"可控塑形\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"导管\\\",\\n            \\\"关系\\\": \\\"使用\\\",\\n            \\\"尾实体\\\": \\\"聚四氟乙烯（PTFE）\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"球囊扩张导管\\\",\\n            \\\"关系\\\": \\\"具有\\\",\\n            \\\"尾实体\\\": \\\"球囊\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"球囊扩张导管\\\",\\n            \\\"关系\\\": \\\"使用\\\",\\n            \\\"尾实体\\\": \\\"聚酰胺\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"球囊扩张导管\\\",\\n            \\\"关系\\\": \\\"使用\\\",\\n            \\\"尾实体\\\": \\\"聚乙烯\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"冠状动脉支架\\\",\\n            \\\"关系\\\": \\\"使用\\\",\\n            \\\"尾实体\\\": \\\"不锈钢支架\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"冠状动脉支架\\\",\\n            \\\"关系\\\": \\\"使用\\\",\\n            \\\"尾实体\\\": \\\"聚乳酸（PLA）支架\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"药物洗脱支架（DES）\\\",\\n            \\\"关系\\\": \\\"属于\\\",\\n            \\\"尾实体\\\": \\\"冠状动脉支架\\\"\\n        }\\n    ]\\n}\\n```\"}', 1, 0, NULL, NULL, '2026-05-08 17:23:45', NULL, NULL, '2026-05-08 17:23:45', NULL);
INSERT INTO `kb_runtime_node` VALUES (15, 1001, 7, 'reply-1774493051863', 3, 1, '{}', '{\"text\":\"```json\\n{\\n    \\\"entities\\\": [\\n        {\\n            \\\"实体文本\\\": \\\"导管\\\",\\n            \\\"实体类型\\\": \\\"器械\\\",\\n            \\\"片段\\\": \\\"导管是介入治疗的“通道”，负责将各种器械和药物精准送达心脏或血管的病变部位。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"超滑涂层\\\",\\n            \\\"实体类型\\\": \\\"功能\\\",\\n            \\\"片段\\\": \\\"超滑涂层：导管表面通常涂有聚四氟乙烯（PTFE）等材料，极大地降低了与血管壁的摩擦力，使得导管能够轻松通过狭窄或迂曲的血管。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"可控塑形\\\",\\n            \\\"实体类型\\\": \\\"功能\\\",\\n            \\\"片段\\\": \\\"可控塑形：导管的远端（前端）可以被塑造成特定的弯度，以适应不同解剖结构的需求。这种塑形通常是通过内部的金属丝（称为“J形导丝”）来实现的。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"聚四氟乙烯（PTFE）\\\",\\n            \\\"实体类型\\\": \\\"材料\\\",\\n            \\\"片段\\\": \\\"导管表面通常涂有聚四氟乙烯（PTFE）等材料，极大地降低了与血管壁的摩擦力，使得导管能够轻松通过狭窄或迂曲的血管。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"球囊扩张导管\\\",\\n            \\\"实体类型\\\": \\\"器械\\\",\\n            \\\"片段\\\": \\\"球囊导管是经皮冠状动脉介入治疗（PCI）中最基础的器械之一。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"球囊\\\",\\n            \\\"实体类型\\\": \\\"功能\\\",\\n            \\\"片段\\\": \\\"其原理是将一个折叠在导管尖端的微型球囊送至血管狭窄处，然后注入液体将其膨胀，从而撑开狭窄的血管，恢复血流。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"聚酰胺\\\",\\n            \\\"实体类型\\\": \\\"材料\\\",\\n            \\\"片段\\\": \\\"球囊材料经历了从早期的天然乳胶到现在的高分子材料（如聚酰胺、聚乙烯等）的演变。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"聚乙烯\\\",\\n            \\\"实体类型\\\": \\\"材料\\\",\\n            \\\"片段\\\": \\\"球囊材料经历了从早期的天然乳胶到现在的高分子材料（如聚酰胺、聚乙烯等）的演变。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"冠状动脉支架\\\",\\n            \\\"实体类型\\\": \\\"器械\\\",\\n            \\\"片段\\\": \\\"支架是介入治疗中最关键的器械，它的作用是在球囊扩张后，为血管提供一个永久的支撑，防止血管回缩或再狭窄。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"不锈钢支架\\\",\\n            \\\"实体类型\\\": \\\"材料\\\",\\n            \\\"片段\\\": \\\"第一代支架：主要为不锈钢支架，优点是强度高，但缺点是永久存留体内，可能引起晚期血栓或限制血管的自然舒缩。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"聚乳酸（PLA）支架\\\",\\n            \\\"实体类型\\\": \\\"材料\\\",\\n            \\\"片段\\\": \\\"第二代支架：为可降解支架，如聚乳酸（PLA）支架。其最大的特点是可在植入后数月到数年内逐渐降解并被人体吸收，最终血管可以恢复自然状态。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"药物洗脱支架（DES）\\\",\\n            \\\"实体类型\\\": \\\"器械\\\",\\n            \\\"片段\\\": \\\"第三代支架：为药物洗脱支架（DES），在金属支架表面涂有可缓慢释放的抗增殖药物（如雷帕霉素）。这种支架既能提供永久支撑，又能抑制血管内膜的过度增生，从而显著降低再狭窄率。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"导丝\\\",\\n            \\\"实体类型\\\": \\\"器械\\\",\\n            \\\"片段\\\": \\\"导丝是介入治疗的“先锋”，负责在血管内开辟通路，引导其他器械到达目的地。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"造影剂\\\",\\n            \\\"实体类型\\\": \\\"器械\\\",\\n            \\\"片段\\\": \\\"造影剂是介入治疗的“眼睛”。通过向血管内注射含碘的造影剂，可以使血管在X线下显影，从而让医生清晰地看到血管的形态、狭窄的位置和程度。\\\",\\n            \\\"属性\\\": {}\\n        }\\n    ],\\n    \\\"relations\\\": [\\n        {\\n            \\\"头实体\\\": \\\"导管\\\",\\n            \\\"关系\\\": \\\"具有\\\",\\n            \\\"尾实体\\\": \\\"超滑涂层\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"导管\\\",\\n            \\\"关系\\\": \\\"具有\\\",\\n            \\\"尾实体\\\": \\\"可控塑形\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"导管\\\",\\n            \\\"关系\\\": \\\"使用\\\",\\n            \\\"尾实体\\\": \\\"聚四氟乙烯（PTFE）\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"球囊扩张导管\\\",\\n            \\\"关系\\\": \\\"具有\\\",\\n            \\\"尾实体\\\": \\\"球囊\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"球囊扩张导管\\\",\\n            \\\"关系\\\": \\\"使用\\\",\\n            \\\"尾实体\\\": \\\"聚酰胺\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"球囊扩张导管\\\",\\n            \\\"关系\\\": \\\"使用\\\",\\n            \\\"尾实体\\\": \\\"聚乙烯\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"冠状动脉支架\\\",\\n            \\\"关系\\\": \\\"使用\\\",\\n            \\\"尾实体\\\": \\\"不锈钢支架\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"冠状动脉支架\\\",\\n            \\\"关系\\\": \\\"使用\\\",\\n            \\\"尾实体\\\": \\\"聚乳酸（PLA）支架\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"药物洗脱支架（DES）\\\",\\n            \\\"关系\\\": \\\"属于\\\",\\n            \\\"尾实体\\\": \\\"冠状动脉支架\\\"\\n        }\\n    ]\\n}\\n```\"}', 1, 0, NULL, NULL, '2026-05-08 17:23:45', NULL, NULL, '2026-05-08 17:23:45', NULL);
INSERT INTO `kb_runtime_node` VALUES (16, 1001, 8, '1', 1, 1, '{\"context\":\"心血管介入治疗器械：从导管到支架的全链条技术解析心血管介入治疗是现代心脏病学的核心技术之一，其成功的关键在于精密的器械。这些器械不仅是手术的工具，更是材料科学与生物医学工程的结晶。本文将深入探讨介入治疗中核心器械的技术原理与材料选择。一、导管系统：介入治疗的“导航车”\\n技术原理：导管是介入治疗的“通道”，负责将各种器械和药物精准送达心脏或血管的病变部位\\n。其核心技术在于“超滑”涂层和“可控塑形”。\\n超滑涂层：导管表面通常涂有聚四氟乙烯（PTFE）等材料，极大地降低了与血管壁的摩擦力，使得导管能够轻松通过狭窄或迂曲的血管。\\n可控塑形：导管的远端（前端）可以被塑造成特定的弯度，以适应不同解剖结构的需求。这种塑形通常是通过内部的金属丝（称为“J形导丝”）来实现的。\\n材料科学：导管的主体材料多为高分子聚合物，如聚氨酯或聚乙烯，这些材料兼具柔韧性和足够的支撑力。\\n二、球囊扩张导管：撑开血管的“微型气球”\\n技术原理：球囊导管是经皮冠状动脉介入治疗（PCI）中最基础的器械之一\\n。其原理是将一个折叠在导管尖端的微型球囊送至血管狭窄处，然后注入液体将其膨胀，从而撑开狭窄的血管，恢复血流。\\n材料科学：球囊材料经历了从早期的天然乳胶到现在的高分子材料（如聚酰胺、聚乙烯等）的演变。现代球囊要求具备高爆破压力（以确保安全）、良好的顺应性（即扩张时能均匀受力）以及快速充盈和排空的能力。\\n三、冠状动脉支架：血管的“永久性骨架”\\n技术原理：支架是介入治疗中最关键的器械，它的作用是在球囊扩张后，为血管提供一个永久的支撑，防止血管回缩或再狭窄\\n。\\n材料科学：支架材料的选择是其技术发展的核心。\\n第一代支架：主要为不锈钢支架，优点是强度高，但缺点是永久存留体内，可能引起晚期血栓或限制血管的自然舒缩。\\n第二代支架：为可降解支架，如聚乳酸（PLA）支架。其最大的特点是可在植入后数月到数年内逐渐降解并被人体吸收，最终血管可以恢复自然状态。\\n第三代支架：为药物洗脱支架（DES），在金属支架表面涂有可缓慢释放的抗增殖药物（如雷帕霉素）。这种支架既能提供永久支撑，又能抑制血管内膜的过度增生，从而显著降低再狭窄率。\\n四、辅助器械：介入治疗的“得力助手”\\n导丝：导丝是介入治疗的“先锋”，负责在血管内开辟通路，引导其他器械到达目的地。现代导丝的尖端非常柔软，可以安全地通过极其复杂的病变，而其尾部则非常坚硬，以保证操作者能够精确地控制其走向。\\n造影剂：造影剂是介入治疗的“眼睛”。通过向血管内注射含碘的造影剂，可以使血管在X线下显影，从而让医生清晰地看到血管的形态、狭窄的位置和程度。\\n\",\"entityCallWord\":\"器械、功能、材料、器械类别\",\"relationCallWord\":\"使用、具有、属于\"}', '{\"1.context\":\"心血管介入治疗器械：从导管到支架的全链条技术解析心血管介入治疗是现代心脏病学的核心技术之一，其成功的关键在于精密的器械。这些器械不仅是手术的工具，更是材料科学与生物医学工程的结晶。本文将深入探讨介入治疗中核心器械的技术原理与材料选择。一、导管系统：介入治疗的“导航车”\\n技术原理：导管是介入治疗的“通道”，负责将各种器械和药物精准送达心脏或血管的病变部位\\n。其核心技术在于“超滑”涂层和“可控塑形”。\\n超滑涂层：导管表面通常涂有聚四氟乙烯（PTFE）等材料，极大地降低了与血管壁的摩擦力，使得导管能够轻松通过狭窄或迂曲的血管。\\n可控塑形：导管的远端（前端）可以被塑造成特定的弯度，以适应不同解剖结构的需求。这种塑形通常是通过内部的金属丝（称为“J形导丝”）来实现的。\\n材料科学：导管的主体材料多为高分子聚合物，如聚氨酯或聚乙烯，这些材料兼具柔韧性和足够的支撑力。\\n二、球囊扩张导管：撑开血管的“微型气球”\\n技术原理：球囊导管是经皮冠状动脉介入治疗（PCI）中最基础的器械之一\\n。其原理是将一个折叠在导管尖端的微型球囊送至血管狭窄处，然后注入液体将其膨胀，从而撑开狭窄的血管，恢复血流。\\n材料科学：球囊材料经历了从早期的天然乳胶到现在的高分子材料（如聚酰胺、聚乙烯等）的演变。现代球囊要求具备高爆破压力（以确保安全）、良好的顺应性（即扩张时能均匀受力）以及快速充盈和排空的能力。\\n三、冠状动脉支架：血管的“永久性骨架”\\n技术原理：支架是介入治疗中最关键的器械，它的作用是在球囊扩张后，为血管提供一个永久的支撑，防止血管回缩或再狭窄\\n。\\n材料科学：支架材料的选择是其技术发展的核心。\\n第一代支架：主要为不锈钢支架，优点是强度高，但缺点是永久存留体内，可能引起晚期血栓或限制血管的自然舒缩。\\n第二代支架：为可降解支架，如聚乳酸（PLA）支架。其最大的特点是可在植入后数月到数年内逐渐降解并被人体吸收，最终血管可以恢复自然状态。\\n第三代支架：为药物洗脱支架（DES），在金属支架表面涂有可缓慢释放的抗增殖药物（如雷帕霉素）。这种支架既能提供永久支撑，又能抑制血管内膜的过度增生，从而显著降低再狭窄率。\\n四、辅助器械：介入治疗的“得力助手”\\n导丝：导丝是介入治疗的“先锋”，负责在血管内开辟通路，引导其他器械到达目的地。现代导丝的尖端非常柔软，可以安全地通过极其复杂的病变，而其尾部则非常坚硬，以保证操作者能够精确地控制其走向。\\n造影剂：造影剂是介入治疗的“眼睛”。通过向血管内注射含碘的造影剂，可以使血管在X线下显影，从而让医生清晰地看到血管的形态、狭窄的位置和程度。\\n\",\"node_1.relationCallWord\":\"使用、具有、属于\",\"node_1.context\":\"心血管介入治疗器械：从导管到支架的全链条技术解析心血管介入治疗是现代心脏病学的核心技术之一，其成功的关键在于精密的器械。这些器械不仅是手术的工具，更是材料科学与生物医学工程的结晶。本文将深入探讨介入治疗中核心器械的技术原理与材料选择。一、导管系统：介入治疗的“导航车”\\n技术原理：导管是介入治疗的“通道”，负责将各种器械和药物精准送达心脏或血管的病变部位\\n。其核心技术在于“超滑”涂层和“可控塑形”。\\n超滑涂层：导管表面通常涂有聚四氟乙烯（PTFE）等材料，极大地降低了与血管壁的摩擦力，使得导管能够轻松通过狭窄或迂曲的血管。\\n可控塑形：导管的远端（前端）可以被塑造成特定的弯度，以适应不同解剖结构的需求。这种塑形通常是通过内部的金属丝（称为“J形导丝”）来实现的。\\n材料科学：导管的主体材料多为高分子聚合物，如聚氨酯或聚乙烯，这些材料兼具柔韧性和足够的支撑力。\\n二、球囊扩张导管：撑开血管的“微型气球”\\n技术原理：球囊导管是经皮冠状动脉介入治疗（PCI）中最基础的器械之一\\n。其原理是将一个折叠在导管尖端的微型球囊送至血管狭窄处，然后注入液体将其膨胀，从而撑开狭窄的血管，恢复血流。\\n材料科学：球囊材料经历了从早期的天然乳胶到现在的高分子材料（如聚酰胺、聚乙烯等）的演变。现代球囊要求具备高爆破压力（以确保安全）、良好的顺应性（即扩张时能均匀受力）以及快速充盈和排空的能力。\\n三、冠状动脉支架：血管的“永久性骨架”\\n技术原理：支架是介入治疗中最关键的器械，它的作用是在球囊扩张后，为血管提供一个永久的支撑，防止血管回缩或再狭窄\\n。\\n材料科学：支架材料的选择是其技术发展的核心。\\n第一代支架：主要为不锈钢支架，优点是强度高，但缺点是永久存留体内，可能引起晚期血栓或限制血管的自然舒缩。\\n第二代支架：为可降解支架，如聚乳酸（PLA）支架。其最大的特点是可在植入后数月到数年内逐渐降解并被人体吸收，最终血管可以恢复自然状态。\\n第三代支架：为药物洗脱支架（DES），在金属支架表面涂有可缓慢释放的抗增殖药物（如雷帕霉素）。这种支架既能提供永久支撑，又能抑制血管内膜的过度增生，从而显著降低再狭窄率。\\n四、辅助器械：介入治疗的“得力助手”\\n导丝：导丝是介入治疗的“先锋”，负责在血管内开辟通路，引导其他器械到达目的地。现代导丝的尖端非常柔软，可以安全地通过极其复杂的病变，而其尾部则非常坚硬，以保证操作者能够精确地控制其走向。\\n造影剂：造影剂是介入治疗的“眼睛”。通过向血管内注射含碘的造影剂，可以使血管在X线下显影，从而让医生清晰地看到血管的形态、狭窄的位置和程度。\\n\",\"node_1.entityCallWord\":\"器械、功能、材料、器械类别\",\"1.entityCallWord\":\"器械、功能、材料、器械类别\",\"1.relationCallWord\":\"使用、具有、属于\"}', 1, 0, NULL, NULL, '2026-05-08 17:55:48', NULL, NULL, '2026-05-08 17:55:48', NULL);
INSERT INTO `kb_runtime_node` VALUES (17, 1001, 8, 'llm-1774493047231', 2, 1, '{}', '{\"llm-1774493047231.text\":\"```json\\n{\\n    \\\"entities\\\": [\\n        {\\n            \\\"实体文本\\\": \\\"导管\\\",\\n            \\\"实体类型\\\": \\\"器械\\\",\\n            \\\"片段\\\": \\\"导管是介入治疗的“通道”，负责将各种器械和药物精准送达心脏或血管的病变部位。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"超滑涂层\\\",\\n            \\\"实体类型\\\": \\\"功能\\\",\\n            \\\"片段\\\": \\\"超滑涂层：导管表面通常涂有聚四氟乙烯（PTFE）等材料，极大地降低了与血管壁的摩擦力，使得导管能够轻松通过狭窄或迂曲的血管。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"可控塑形\\\",\\n            \\\"实体类型\\\": \\\"功能\\\",\\n            \\\"片段\\\": \\\"可控塑形：导管的远端（前端）可以被塑造成特定的弯度，以适应不同解剖结构的需求。这种塑形通常是通过内部的金属丝（称为“J形导丝”）来实现的。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"聚四氟乙烯（PTFE）\\\",\\n            \\\"实体类型\\\": \\\"材料\\\",\\n            \\\"片段\\\": \\\"导管表面通常涂有聚四氟乙烯（PTFE）等材料，极大地降低了与血管壁的摩擦力，使得导管能够轻松通过狭窄或迂曲的血管。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"球囊扩张导管\\\",\\n            \\\"实体类型\\\": \\\"器械\\\",\\n            \\\"片段\\\": \\\"球囊导管是经皮冠状动脉介入治疗（PCI）中最基础的器械之一。其原理是将一个折叠在导管尖端的微型球囊送至血管狭窄处，然后注入液体将其膨胀，从而撑开狭窄的血管，恢复血流。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"聚酰胺\\\",\\n            \\\"实体类型\\\": \\\"材料\\\",\\n            \\\"片段\\\": \\\"球囊材料经历了从早期的天然乳胶到现在的高分子材料（如聚酰胺、聚乙烯等）的演变。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"聚乙烯\\\",\\n            \\\"实体类型\\\": \\\"材料\\\",\\n            \\\"片段\\\": \\\"球囊材料经历了从早期的天然乳胶到现在的高分子材料（如聚酰胺、聚乙烯等）的演变。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"冠状动脉支架\\\",\\n            \\\"实体类型\\\": \\\"器械\\\",\\n            \\\"片段\\\": \\\"支架是介入治疗中最关键的器械，它的作用是在球囊扩张后，为血管提供一个永久的支撑，防止血管回缩或再狭窄。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"不锈钢支架\\\",\\n            \\\"实体类型\\\": \\\"器械\\\",\\n            \\\"片段\\\": \\\"第一代支架：主要为不锈钢支架，优点是强度高，但缺点是永久存留体内，可能引起晚期血栓或限制血管的自然舒缩。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"聚乳酸（PLA）支架\\\",\\n            \\\"实体类型\\\": \\\"器械\\\",\\n            \\\"片段\\\": \\\"第二代支架：为可降解支架，如聚乳酸（PLA）支架。其最大的特点是可在植入后数月到数年内逐渐降解并被人体吸收，最终血管可以恢复自然状态。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"药物洗脱支架（DES）\\\",\\n            \\\"实体类型\\\": \\\"器械\\\",\\n            \\\"片段\\\": \\\"第三代支架：为药物洗脱支架（DES），在金属支架表面涂有可缓慢释放的抗增殖药物（如雷帕霉素）。这种支架既能提供永久支撑，又能抑制血管内膜的过度增生，从而显著降低再狭窄率。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"导丝\\\",\\n            \\\"实体类型\\\": \\\"器械\\\",\\n            \\\"片段\\\": \\\"导丝是介入治疗的“先锋”，负责在血管内开辟通路，引导其他器械到达目的地。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"造影剂\\\",\\n            \\\"实体类型\\\": \\\"器械\\\",\\n            \\\"片段\\\": \\\"造影剂是介入治疗的“眼睛”。通过向血管内注射含碘的造影剂，可以使血管在X线下显影，从而让医生清晰地看到血管的形态、狭窄的位置和程度。\\\",\\n            \\\"属性\\\": {}\\n        }\\n    ],\\n    \\\"relations\\\": [\\n        {\\n            \\\"头实体\\\": \\\"导管\\\",\\n            \\\"关系\\\": \\\"具有\\\",\\n            \\\"尾实体\\\": \\\"超滑涂层\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"导管\\\",\\n            \\\"关系\\\": \\\"具有\\\",\\n            \\\"尾实体\\\": \\\"可控塑形\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"导管\\\",\\n            \\\"关系\\\": \\\"使用\\\",\\n            \\\"尾实体\\\": \\\"聚四氟乙烯（PTFE）\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"球囊扩张导管\\\",\\n            \\\"关系\\\": \\\"使用\\\",\\n            \\\"尾实体\\\": \\\"聚酰胺\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"球囊扩张导管\\\",\\n            \\\"关系\\\": \\\"使用\\\",\\n            \\\"尾实体\\\": \\\"聚乙烯\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"冠状动脉支架\\\",\\n            \\\"关系\\\": \\\"属于\\\",\\n            \\\"尾实体\\\": \\\"器械\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"不锈钢支架\\\",\\n            \\\"关系\\\": \\\"属于\\\",\\n            \\\"尾实体\\\": \\\"器械\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"聚乳酸（PLA）支架\\\",\\n            \\\"关系\\\": \\\"属于\\\",\\n            \\\"尾实体\\\": \\\"器械\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"药物洗脱支架（DES）\\\",\\n            \\\"关系\\\": \\\"属于\\\",\\n            \\\"尾实体\\\": \\\"器械\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"导丝\\\",\\n            \\\"关系\\\": \\\"属于\\\",\\n            \\\"尾实体\\\": \\\"器械\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"造影剂\\\",\\n            \\\"关系\\\": \\\"属于\\\",\\n            \\\"尾实体\\\": \\\"器械\\\"\\n        }\\n    ]\\n}\\n```\"}', 1, 0, NULL, NULL, '2026-05-08 17:57:13', NULL, NULL, '2026-05-08 17:57:13', NULL);
INSERT INTO `kb_runtime_node` VALUES (18, 1001, 8, 'reply-1774493051863', 3, 1, '{}', '{\"text\":\"```json\\n{\\n    \\\"entities\\\": [\\n        {\\n            \\\"实体文本\\\": \\\"导管\\\",\\n            \\\"实体类型\\\": \\\"器械\\\",\\n            \\\"片段\\\": \\\"导管是介入治疗的“通道”，负责将各种器械和药物精准送达心脏或血管的病变部位。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"超滑涂层\\\",\\n            \\\"实体类型\\\": \\\"功能\\\",\\n            \\\"片段\\\": \\\"超滑涂层：导管表面通常涂有聚四氟乙烯（PTFE）等材料，极大地降低了与血管壁的摩擦力，使得导管能够轻松通过狭窄或迂曲的血管。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"可控塑形\\\",\\n            \\\"实体类型\\\": \\\"功能\\\",\\n            \\\"片段\\\": \\\"可控塑形：导管的远端（前端）可以被塑造成特定的弯度，以适应不同解剖结构的需求。这种塑形通常是通过内部的金属丝（称为“J形导丝”）来实现的。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"聚四氟乙烯（PTFE）\\\",\\n            \\\"实体类型\\\": \\\"材料\\\",\\n            \\\"片段\\\": \\\"导管表面通常涂有聚四氟乙烯（PTFE）等材料，极大地降低了与血管壁的摩擦力，使得导管能够轻松通过狭窄或迂曲的血管。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"球囊扩张导管\\\",\\n            \\\"实体类型\\\": \\\"器械\\\",\\n            \\\"片段\\\": \\\"球囊导管是经皮冠状动脉介入治疗（PCI）中最基础的器械之一。其原理是将一个折叠在导管尖端的微型球囊送至血管狭窄处，然后注入液体将其膨胀，从而撑开狭窄的血管，恢复血流。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"聚酰胺\\\",\\n            \\\"实体类型\\\": \\\"材料\\\",\\n            \\\"片段\\\": \\\"球囊材料经历了从早期的天然乳胶到现在的高分子材料（如聚酰胺、聚乙烯等）的演变。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"聚乙烯\\\",\\n            \\\"实体类型\\\": \\\"材料\\\",\\n            \\\"片段\\\": \\\"球囊材料经历了从早期的天然乳胶到现在的高分子材料（如聚酰胺、聚乙烯等）的演变。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"冠状动脉支架\\\",\\n            \\\"实体类型\\\": \\\"器械\\\",\\n            \\\"片段\\\": \\\"支架是介入治疗中最关键的器械，它的作用是在球囊扩张后，为血管提供一个永久的支撑，防止血管回缩或再狭窄。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"不锈钢支架\\\",\\n            \\\"实体类型\\\": \\\"器械\\\",\\n            \\\"片段\\\": \\\"第一代支架：主要为不锈钢支架，优点是强度高，但缺点是永久存留体内，可能引起晚期血栓或限制血管的自然舒缩。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"聚乳酸（PLA）支架\\\",\\n            \\\"实体类型\\\": \\\"器械\\\",\\n            \\\"片段\\\": \\\"第二代支架：为可降解支架，如聚乳酸（PLA）支架。其最大的特点是可在植入后数月到数年内逐渐降解并被人体吸收，最终血管可以恢复自然状态。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"药物洗脱支架（DES）\\\",\\n            \\\"实体类型\\\": \\\"器械\\\",\\n            \\\"片段\\\": \\\"第三代支架：为药物洗脱支架（DES），在金属支架表面涂有可缓慢释放的抗增殖药物（如雷帕霉素）。这种支架既能提供永久支撑，又能抑制血管内膜的过度增生，从而显著降低再狭窄率。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"导丝\\\",\\n            \\\"实体类型\\\": \\\"器械\\\",\\n            \\\"片段\\\": \\\"导丝是介入治疗的“先锋”，负责在血管内开辟通路，引导其他器械到达目的地。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"造影剂\\\",\\n            \\\"实体类型\\\": \\\"器械\\\",\\n            \\\"片段\\\": \\\"造影剂是介入治疗的“眼睛”。通过向血管内注射含碘的造影剂，可以使血管在X线下显影，从而让医生清晰地看到血管的形态、狭窄的位置和程度。\\\",\\n            \\\"属性\\\": {}\\n        }\\n    ],\\n    \\\"relations\\\": [\\n        {\\n            \\\"头实体\\\": \\\"导管\\\",\\n            \\\"关系\\\": \\\"具有\\\",\\n            \\\"尾实体\\\": \\\"超滑涂层\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"导管\\\",\\n            \\\"关系\\\": \\\"具有\\\",\\n            \\\"尾实体\\\": \\\"可控塑形\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"导管\\\",\\n            \\\"关系\\\": \\\"使用\\\",\\n            \\\"尾实体\\\": \\\"聚四氟乙烯（PTFE）\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"球囊扩张导管\\\",\\n            \\\"关系\\\": \\\"使用\\\",\\n            \\\"尾实体\\\": \\\"聚酰胺\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"球囊扩张导管\\\",\\n            \\\"关系\\\": \\\"使用\\\",\\n            \\\"尾实体\\\": \\\"聚乙烯\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"冠状动脉支架\\\",\\n            \\\"关系\\\": \\\"属于\\\",\\n            \\\"尾实体\\\": \\\"器械\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"不锈钢支架\\\",\\n            \\\"关系\\\": \\\"属于\\\",\\n            \\\"尾实体\\\": \\\"器械\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"聚乳酸（PLA）支架\\\",\\n            \\\"关系\\\": \\\"属于\\\",\\n            \\\"尾实体\\\": \\\"器械\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"药物洗脱支架（DES）\\\",\\n            \\\"关系\\\": \\\"属于\\\",\\n            \\\"尾实体\\\": \\\"器械\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"导丝\\\",\\n            \\\"关系\\\": \\\"属于\\\",\\n            \\\"尾实体\\\": \\\"器械\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"造影剂\\\",\\n            \\\"关系\\\": \\\"属于\\\",\\n            \\\"尾实体\\\": \\\"器械\\\"\\n        }\\n    ]\\n}\\n```\"}', 1, 0, NULL, NULL, '2026-05-08 17:57:13', NULL, NULL, '2026-05-08 17:57:13', NULL);
INSERT INTO `kb_runtime_node` VALUES (19, 1001, 9, '1', 1, 1, '{\"context\":\"心血管介入治疗器械：从导管到支架的全链条技术解析心血管介入治疗是现代心脏病学的核心技术之一，其成功的关键在于精密的器械。这些器械不仅是手术的工具，更是材料科学与生物医学工程的结晶。本文将深入探讨介入治疗中核心器械的技术原理与材料选择。一、导管系统：介入治疗的“导航车”\\n技术原理：导管是介入治疗的“通道”，负责将各种器械和药物精准送达心脏或血管的病变部位\\n。其核心技术在于“超滑”涂层和“可控塑形”。\\n超滑涂层：导管表面通常涂有聚四氟乙烯（PTFE）等材料，极大地降低了与血管壁的摩擦力，使得导管能够轻松通过狭窄或迂曲的血管。\\n可控塑形：导管的远端（前端）可以被塑造成特定的弯度，以适应不同解剖结构的需求。这种塑形通常是通过内部的金属丝（称为“J形导丝”）来实现的。\\n材料科学：导管的主体材料多为高分子聚合物，如聚氨酯或聚乙烯，这些材料兼具柔韧性和足够的支撑力。\\n二、球囊扩张导管：撑开血管的“微型气球”\\n技术原理：球囊导管是经皮冠状动脉介入治疗（PCI）中最基础的器械之一\\n。其原理是将一个折叠在导管尖端的微型球囊送至血管狭窄处，然后注入液体将其膨胀，从而撑开狭窄的血管，恢复血流。\\n材料科学：球囊材料经历了从早期的天然乳胶到现在的高分子材料（如聚酰胺、聚乙烯等）的演变。现代球囊要求具备高爆破压力（以确保安全）、良好的顺应性（即扩张时能均匀受力）以及快速充盈和排空的能力。\\n三、冠状动脉支架：血管的“永久性骨架”\\n技术原理：支架是介入治疗中最关键的器械，它的作用是在球囊扩张后，为血管提供一个永久的支撑，防止血管回缩或再狭窄\\n。\\n材料科学：支架材料的选择是其技术发展的核心。\\n第一代支架：主要为不锈钢支架，优点是强度高，但缺点是永久存留体内，可能引起晚期血栓或限制血管的自然舒缩。\\n第二代支架：为可降解支架，如聚乳酸（PLA）支架。其最大的特点是可在植入后数月到数年内逐渐降解并被人体吸收，最终血管可以恢复自然状态。\\n第三代支架：为药物洗脱支架（DES），在金属支架表面涂有可缓慢释放的抗增殖药物（如雷帕霉素）。这种支架既能提供永久支撑，又能抑制血管内膜的过度增生，从而显著降低再狭窄率。\\n四、辅助器械：介入治疗的“得力助手”\\n导丝：导丝是介入治疗的“先锋”，负责在血管内开辟通路，引导其他器械到达目的地。现代导丝的尖端非常柔软，可以安全地通过极其复杂的病变，而其尾部则非常坚硬，以保证操作者能够精确地控制其走向。\\n造影剂：造影剂是介入治疗的“眼睛”。通过向血管内注射含碘的造影剂，可以使血管在X线下显影，从而让医生清晰地看到血管的形态、狭窄的位置和程度。\\n\",\"entityCallWord\":\"器械、功能、材料、器械类别\",\"relationCallWord\":\"使用、具有、属于\"}', '{\"1.context\":\"心血管介入治疗器械：从导管到支架的全链条技术解析心血管介入治疗是现代心脏病学的核心技术之一，其成功的关键在于精密的器械。这些器械不仅是手术的工具，更是材料科学与生物医学工程的结晶。本文将深入探讨介入治疗中核心器械的技术原理与材料选择。一、导管系统：介入治疗的“导航车”\\n技术原理：导管是介入治疗的“通道”，负责将各种器械和药物精准送达心脏或血管的病变部位\\n。其核心技术在于“超滑”涂层和“可控塑形”。\\n超滑涂层：导管表面通常涂有聚四氟乙烯（PTFE）等材料，极大地降低了与血管壁的摩擦力，使得导管能够轻松通过狭窄或迂曲的血管。\\n可控塑形：导管的远端（前端）可以被塑造成特定的弯度，以适应不同解剖结构的需求。这种塑形通常是通过内部的金属丝（称为“J形导丝”）来实现的。\\n材料科学：导管的主体材料多为高分子聚合物，如聚氨酯或聚乙烯，这些材料兼具柔韧性和足够的支撑力。\\n二、球囊扩张导管：撑开血管的“微型气球”\\n技术原理：球囊导管是经皮冠状动脉介入治疗（PCI）中最基础的器械之一\\n。其原理是将一个折叠在导管尖端的微型球囊送至血管狭窄处，然后注入液体将其膨胀，从而撑开狭窄的血管，恢复血流。\\n材料科学：球囊材料经历了从早期的天然乳胶到现在的高分子材料（如聚酰胺、聚乙烯等）的演变。现代球囊要求具备高爆破压力（以确保安全）、良好的顺应性（即扩张时能均匀受力）以及快速充盈和排空的能力。\\n三、冠状动脉支架：血管的“永久性骨架”\\n技术原理：支架是介入治疗中最关键的器械，它的作用是在球囊扩张后，为血管提供一个永久的支撑，防止血管回缩或再狭窄\\n。\\n材料科学：支架材料的选择是其技术发展的核心。\\n第一代支架：主要为不锈钢支架，优点是强度高，但缺点是永久存留体内，可能引起晚期血栓或限制血管的自然舒缩。\\n第二代支架：为可降解支架，如聚乳酸（PLA）支架。其最大的特点是可在植入后数月到数年内逐渐降解并被人体吸收，最终血管可以恢复自然状态。\\n第三代支架：为药物洗脱支架（DES），在金属支架表面涂有可缓慢释放的抗增殖药物（如雷帕霉素）。这种支架既能提供永久支撑，又能抑制血管内膜的过度增生，从而显著降低再狭窄率。\\n四、辅助器械：介入治疗的“得力助手”\\n导丝：导丝是介入治疗的“先锋”，负责在血管内开辟通路，引导其他器械到达目的地。现代导丝的尖端非常柔软，可以安全地通过极其复杂的病变，而其尾部则非常坚硬，以保证操作者能够精确地控制其走向。\\n造影剂：造影剂是介入治疗的“眼睛”。通过向血管内注射含碘的造影剂，可以使血管在X线下显影，从而让医生清晰地看到血管的形态、狭窄的位置和程度。\\n\",\"node_1.relationCallWord\":\"使用、具有、属于\",\"node_1.context\":\"心血管介入治疗器械：从导管到支架的全链条技术解析心血管介入治疗是现代心脏病学的核心技术之一，其成功的关键在于精密的器械。这些器械不仅是手术的工具，更是材料科学与生物医学工程的结晶。本文将深入探讨介入治疗中核心器械的技术原理与材料选择。一、导管系统：介入治疗的“导航车”\\n技术原理：导管是介入治疗的“通道”，负责将各种器械和药物精准送达心脏或血管的病变部位\\n。其核心技术在于“超滑”涂层和“可控塑形”。\\n超滑涂层：导管表面通常涂有聚四氟乙烯（PTFE）等材料，极大地降低了与血管壁的摩擦力，使得导管能够轻松通过狭窄或迂曲的血管。\\n可控塑形：导管的远端（前端）可以被塑造成特定的弯度，以适应不同解剖结构的需求。这种塑形通常是通过内部的金属丝（称为“J形导丝”）来实现的。\\n材料科学：导管的主体材料多为高分子聚合物，如聚氨酯或聚乙烯，这些材料兼具柔韧性和足够的支撑力。\\n二、球囊扩张导管：撑开血管的“微型气球”\\n技术原理：球囊导管是经皮冠状动脉介入治疗（PCI）中最基础的器械之一\\n。其原理是将一个折叠在导管尖端的微型球囊送至血管狭窄处，然后注入液体将其膨胀，从而撑开狭窄的血管，恢复血流。\\n材料科学：球囊材料经历了从早期的天然乳胶到现在的高分子材料（如聚酰胺、聚乙烯等）的演变。现代球囊要求具备高爆破压力（以确保安全）、良好的顺应性（即扩张时能均匀受力）以及快速充盈和排空的能力。\\n三、冠状动脉支架：血管的“永久性骨架”\\n技术原理：支架是介入治疗中最关键的器械，它的作用是在球囊扩张后，为血管提供一个永久的支撑，防止血管回缩或再狭窄\\n。\\n材料科学：支架材料的选择是其技术发展的核心。\\n第一代支架：主要为不锈钢支架，优点是强度高，但缺点是永久存留体内，可能引起晚期血栓或限制血管的自然舒缩。\\n第二代支架：为可降解支架，如聚乳酸（PLA）支架。其最大的特点是可在植入后数月到数年内逐渐降解并被人体吸收，最终血管可以恢复自然状态。\\n第三代支架：为药物洗脱支架（DES），在金属支架表面涂有可缓慢释放的抗增殖药物（如雷帕霉素）。这种支架既能提供永久支撑，又能抑制血管内膜的过度增生，从而显著降低再狭窄率。\\n四、辅助器械：介入治疗的“得力助手”\\n导丝：导丝是介入治疗的“先锋”，负责在血管内开辟通路，引导其他器械到达目的地。现代导丝的尖端非常柔软，可以安全地通过极其复杂的病变，而其尾部则非常坚硬，以保证操作者能够精确地控制其走向。\\n造影剂：造影剂是介入治疗的“眼睛”。通过向血管内注射含碘的造影剂，可以使血管在X线下显影，从而让医生清晰地看到血管的形态、狭窄的位置和程度。\\n\",\"node_1.entityCallWord\":\"器械、功能、材料、器械类别\",\"1.entityCallWord\":\"器械、功能、材料、器械类别\",\"1.relationCallWord\":\"使用、具有、属于\"}', 1, 0, NULL, NULL, '2026-05-08 18:00:32', NULL, NULL, '2026-05-08 18:00:32', NULL);
INSERT INTO `kb_runtime_node` VALUES (20, 1001, 9, 'llm-1774493047231', 2, 1, '{}', '{\"llm-1774493047231.text\":\"```json\\n{\\n    \\\"entities\\\": [\\n        {\\n            \\\"实体文本\\\": \\\"导管\\\",\\n            \\\"实体类型\\\": \\\"器械\\\",\\n            \\\"片段\\\": \\\"导管是介入治疗的“通道”，负责将各种器械和药物精准送达心脏或血管的病变部位。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"超滑涂层\\\",\\n            \\\"实体类型\\\": \\\"功能\\\",\\n            \\\"片段\\\": \\\"超滑涂层：导管表面通常涂有聚四氟乙烯（PTFE）等材料，极大地降低了与血管壁的摩擦力，使得导管能够轻松通过狭窄或迂曲的血管。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"可控塑形\\\",\\n            \\\"实体类型\\\": \\\"功能\\\",\\n            \\\"片段\\\": \\\"可控塑形：导管的远端（前端）可以被塑造成特定的弯度，以适应不同解剖结构的需求。这种塑形通常是通过内部的金属丝（称为“J形导丝”）来实现的。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"聚四氟乙烯（PTFE）\\\",\\n            \\\"实体类型\\\": \\\"材料\\\",\\n            \\\"片段\\\": \\\"导管表面通常涂有聚四氟乙烯（PTFE）等材料，极大地降低了与血管壁的摩擦力，使得导管能够轻松通过狭窄或迂曲的血管。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"高分子聚合物\\\",\\n            \\\"实体类型\\\": \\\"材料\\\",\\n            \\\"片段\\\": \\\"导管的主体材料多为高分子聚合物，如聚氨酯或聚乙烯，这些材料兼具柔韧性和足够的支撑力。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"球囊扩张导管\\\",\\n            \\\"实体类型\\\": \\\"器械\\\",\\n            \\\"片段\\\": \\\"球囊导管是经皮冠状动脉介入治疗（PCI）中最基础的器械之一。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"聚酰胺\\\",\\n            \\\"实体类型\\\": \\\"材料\\\",\\n            \\\"片段\\\": \\\"现代球囊要求具备高爆破压力（以确保安全）、良好的顺应性（即扩张时能均匀受力）以及快速充盈和排空的能力。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"聚乙烯\\\",\\n            \\\"实体类型\\\": \\\"材料\\\",\\n            \\\"片段\\\": \\\"现代球囊要求具备高爆破压力（以确保安全）、良好的顺应性（即扩张时能均匀受力）以及快速充盈和排空的能力。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"冠状动脉支架\\\",\\n            \\\"实体类型\\\": \\\"器械\\\",\\n            \\\"片段\\\": \\\"支架是介入治疗中最关键的器械，它的作用是在球囊扩张后，为血管提供一个永久的支撑，防止血管回缩或再狭窄。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"不锈钢支架\\\",\\n            \\\"实体类型\\\": \\\"器械\\\",\\n            \\\"片段\\\": \\\"第一代支架：主要为不锈钢支架，优点是强度高，但缺点是永久存留体内，可能引起晚期血栓或限制血管的自然舒缩。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"可降解支架\\\",\\n            \\\"实体类型\\\": \\\"器械\\\",\\n            \\\"片段\\\": \\\"第二代支架：为可降解支架，如聚乳酸（PLA）支架。其最大的特点是可在植入后数月到数年内逐渐降解并被人体吸收，最终血管可以恢复自然状态。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"药物洗脱支架（DES）\\\",\\n            \\\"实体类型\\\": \\\"器械\\\",\\n            \\\"片段\\\": \\\"第三代支架：为药物洗脱支架（DES），在金属支架表面涂有可缓慢释放的抗增殖药物（如雷帕霉素）。这种支架既能提供永久支撑，又能抑制血管内膜的过度增生，从而显著降低再狭窄率。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"导丝\\\",\\n            \\\"实体类型\\\": \\\"器械\\\",\\n            \\\"片段\\\": \\\"导丝是介入治疗的“先锋”，负责在血管内开辟通路，引导其他器械到达目的地。\\\",\\n            \\\"属性\\\": {}\\n        },\\n        {\\n            \\\"实体文本\\\": \\\"造影剂\\\",\\n            \\\"实体类型\\\": \\\"器械\\\",\\n            \\\"片段\\\": \\\"造影剂是介入治疗的“眼睛”。通过向血管内注射含碘的造影剂，可以使血管在X线下显影，从而让医生清晰地看到血管的形态、狭窄的位置和程度。\\\",\\n            \\\"属性\\\": {}\\n        }\\n    ],\\n    \\\"relations\\\": [\\n        {\\n            \\\"头实体\\\": \\\"导管\\\",\\n            \\\"关系\\\": \\\"具有\\\",\\n            \\\"尾实体\\\": \\\"超滑涂层\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"导管\\\",\\n            \\\"关系\\\": \\\"具有\\\",\\n            \\\"尾实体\\\": \\\"可控塑形\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"导管\\\",\\n            \\\"关系\\\": \\\"使用\\\",\\n            \\\"尾实体\\\": \\\"聚四氟乙烯（PTFE）\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"导管\\\",\\n            \\\"关系\\\": \\\"使用\\\",\\n            \\\"尾实体\\\": \\\"高分子聚合物\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"球囊扩张导管\\\",\\n            \\\"关系\\\": \\\"使用\\\",\\n            \\\"尾实体\\\": \\\"聚酰胺\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"球囊扩张导管\\\",\\n            \\\"关系\\\": \\\"使用\\\",\\n            \\\"尾实体\\\": \\\"聚乙烯\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"冠状动脉支架\\\",\\n            \\\"关系\\\": \\\"属于\\\",\\n            \\\"尾实体\\\": \\\"器械\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"不锈钢支架\\\",\\n            \\\"关系\\\": \\\"属于\\\",\\n            \\\"尾实体\\\": \\\"器械\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"可降解支架\\\",\\n            \\\"关系\\\": \\\"属于\\\",\\n            \\\"尾实体\\\": \\\"器械\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"药物洗脱支架（DES）\\\",\\n            \\\"关系\\\": \\\"属于\\\",\\n            \\\"尾实体\\\": \\\"器械\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"导丝\\\",\\n            \\\"关系\\\": \\\"属于\\\",\\n            \\\"尾实体\\\": \\\"器械\\\"\\n        },\\n        {\\n            \\\"头实体\\\": \\\"造影剂\\\",\\n            \\\"关系\\\": \\\"属于\\\",\\n            \\\"尾实体\\\": \\\"器械\\\"\\n        }\\n    ]\\n}\\n```\"}', 1, 0, NULL, NULL, '2026-05-08 18:01:53', NULL, NULL, '2026-05-08 18:01:53', NULL);
