INSERT INTO `kg_knowledge_document` VALUES (1, 1001, 1, '疾病与诊断', '疾病与诊断：医学实践的核心要素.docx', '/2026/05/14/6a0544aab3541c9296b057dc.docx', '阐述临床诊断的标准流程、鉴别诊断逻辑与循证医学在实践中的具体应用。', 1, 0, '小桐', 1, '2026-05-14 11:42:38', '小桐', NULL, '2026-05-15 15:28:11', '核心业务文档，供临床路径参考');
INSERT INTO `kg_knowledge_document` VALUES (2, 1001, 2, '治疗与干预', '疾病治疗与干预综合指南.docx', '/2026/05/14/6a0544e9b3541c9296b057de.docx', '聚焦各类疾病的综合管理策略，介绍以患者为中心的个性化干预措施与康复方案。', 1, 0, '小桐', 1, '2026-05-14 11:43:39', '小桐', NULL, '2026-05-15 15:28:11', '2026版最新修订，含非药物干预章节');
INSERT INTO `kg_knowledge_document` VALUES (3, 1001, 3, '药物与器械', '药物与医疗器械应用指南.docx', '/2026/05/14/6a0544f3b3541c9296b057df.docx', '深度解析药械组合产品的临床应用规范、不良反应监测及注册合规要求。', 1, 0, '小桐', 1, '2026-05-14 11:43:48', '小桐', NULL, '2026-05-15 15:28:11', '需结合最新药监局法规同步更新');
INSERT INTO `kg_knowledge_document` VALUES (4, 1001, 5, '人员与机构', '医疗体系中的人力资源与机构组织.docx', '/2026/05/14/6a054501b3541c9296b057e0.docx', '剖析现代化医疗机构的组织架构设计、核心人才梯队管理与绩效考核体系。', 1, 0, '小桐', 1, '2026-05-14 11:44:03', '小桐', NULL, '2026-05-15 15:28:11', '适用于医院管理层培训资料');
INSERT INTO `kg_knowledge_document` VALUES (5, 1001, 4, '人体与功能', '医学与健康科学综合文档.docx', '/2026/05/14/6a05451ab3541c9296b057e1.docx', '概述当前医学前沿发展趋势、多学科诊疗(MDT)融合及医学科研人员的职业规划。', 1, 0, '小桐', 1, '2026-05-14 11:44:27', '小桐', NULL, '2026-05-15 15:28:11', '包含年度健康科学论坛会议纪要');
INSERT INTO `kg_knowledge_document` VALUES (6, 1001, 6, '疾病实体', '疾病实体识别技术综述.pdf', '/2026/05/15/6a06c97eb354497c155b7b49.pdf', '基于深度学习与自然语言处理（NLP）的疾病实体识别（NER）技术，经历了从早期依赖人工特征工程的统计模型，到如今利用预训练语言模型自动提取深层语义特征的显著演进。在技术发展的初期，NER主要依赖基于规则和词典的方法，以及隐马尔可夫模型（HMM）、支持向量机（SVM）和条件随机场（CRF）等统计机器学习模型，这些方法虽然在特定领域取得了一定成效，但其性能高度依赖于特征工程的质量，且泛化能力有限。\r', 1, 0, '小桐', 1, '2026-05-15 15:21:38', '小桐', NULL, '2026-05-15 15:28:11', '知识图谱构建技术底层参考资料');
INSERT INTO `kg_knowledge_document` VALUES (7, 1001, 1, '疾病与诊断', '疾病百科全书.pdf', '/2026/05/15/6a06c9e8b354497c155b7b4a.pdf', '收录ICD-11标准下的常见及罕见疾病定义、流行病学特征、病因及病理机制。', 1, 0, '小桐', 1, '2026-05-15 15:23:21', '小桐', NULL, '2026-05-15 15:28:11', '基础知识库，数据量较大需定期同步');
INSERT INTO `kg_knowledge_document` VALUES (8, 1001, 7, '诊断实体', '疾病诊断综合指南.docx', '/2026/05/15/6a06ca10b354497c155b7b4b.docx', '详解影像学检查、实验室检验及病理诊断在疾病确诊中的综合应用与判读标准。', 1, 0, '小桐', 1, '2026-05-15 15:24:01', '小桐', NULL, '2026-05-15 15:28:11', '重点更新了肿瘤标志物检测标准');
INSERT INTO `kg_knowledge_document` VALUES (9, 1001, 8, '治疗方法', '疾病诊断与治疗综合指南.docx', '/2026/05/15/6a06ca26b354497c155b7b4c.docx', '针对特定病种，提供从早期筛查、确诊到全周期治疗方案的标准化临床路径。', 1, 0, '小桐', 1, '2026-05-15 15:24:23', '小桐', NULL, '2026-05-15 15:28:11', '临床一线医生必备速查手册');
INSERT INTO `kg_knowledge_document` VALUES (10, 1001, 12, '解剖结构', '人体解剖结构详解.docx', '/2026/05/15/6a06ca35b354497c155b7b4d.docx', '系统介绍人体骨骼、肌肉、内脏及神经系统等宏观与微观解剖学结构特征。', 1, 0, '小桐', 1, '2026-05-15 15:24:44', '小桐', NULL, '2026-05-15 15:28:11', '包含3D解剖模型索引链接');
INSERT INTO `kg_knowledge_document` VALUES (11, 1001, 13, '生理功能', '人体解剖结构与生理功能详解.docx', '/2026/05/15/6a06ca49b354497c155b7b4e.docx', '系统阐述人体各大系统的解剖形态，并深入解析其对应的生理功能与运作机制。', 1, 0, '小桐', 1, '2026-05-15 15:25:00', '小桐', NULL, '2026-05-15 15:25:00', '涵盖运动、消化、呼吸及神经等核心系统，适用于医学基础教学与临床参考。');
