INSERT INTO `kmc_document_segment` VALUES (223, 1001, '常见药物.txt', 10, '0cc3d2e4-89ee-46cf-b63c-8ad4830511b0', 3, NULL, 'ARB，急性水肿需维护呼吸道。\n新型口服抗凝药导致皮下淤斑、便血或颅内出血的风险增加，INR显著升高时应调整剂量或应用拮抗剂。\r\n六、常见用药误区\r\n为了快速退烧频繁交替服用布洛芬与对乙酰氨基酚，易掩盖病情且损伤肝肾，应遵医嘱并监测体温趋势。\r\n普通感冒多为病毒感染，预防性使用抗生素不仅无益，反而促进耐药并破坏肠道菌群。\r\n长期服用质子泵抑制剂并非零风险，八周以上需评估感染、骨折及电解质紊乱风险，必要时改用H2受体拮抗剂或按需服用。\r\n误以为中成药与西药无冲突，一些含马兜铃酸或炙甘草的复方制剂可致肾毒性或心律失常，使用前应核对成分避免重复用药。\r\n七、家庭药箱配置建议\n感冒发热场景：对乙酰氨基酚、布洛芬、等渗盐水喷鼻剂。\n胃肠不适：奥美拉唑、蒙脱石散、口服补液盐。\n轻伤处理：碘伏、创可贴、弹性绷带。\n过敏反应：西替利嗪或氯雷他定，如有呼吸困难需立即就医。\n慢性病管理：高血压患者常备缬沙坦或硝苯地平控释片及电子血压计；糖尿病患者常备二甲双胍、速效胰岛素和葡萄糖片以防低血糖。\r\n八、未来趋势与展望\n精准医学将利用药物基因组学指导个体化选药，例如根据CYP2C19基因型调整氯吡格雷剂量或更换替格瑞洛。长效制剂的发展使得GLP-1类似物可周注射一次，精神疾病长效针剂可半年给药一次，显著改善依从性。数字健康通过智能血糖仪与云端平台实时监测血糖，利用人工智能预测低血糖并推送提醒。复方制剂和固定剂量复方片（例如“单片双降”降压药、阿托伐他汀/依泽替米贝组合）简化了处方结构，提高了疗效与依从性。\r\n结语\n常用药物种类繁多、用途广泛，既能在专业医疗机构发挥救命作用，也能在家庭场景中提供第一时间的健康守护。掌握药理机制、适应证与不良反应，遵循个体化与循证医学原则，是每一名医护人员与公众用药安全的核心。希望本文能帮助读者建立系统、科学的用药知识框架，在日常健康管理与疾病治疗中作出更安全、更有效的选择。', 'ARB，急性水肿需维护呼吸道。\n新型口服抗凝药导致皮下淤斑、便血或颅内出血的风险增加，INR显著升高时应调整剂量或应用拮抗剂。\r\n六、常见用药误区\r\n为了快速退烧频繁交替服用布洛芬与对乙酰氨基酚，易掩盖病情且损伤肝肾，应遵医嘱并监测体温趋势。\r\n普通感冒多为病毒感染，预防性使用抗生素不仅无益，反而促进耐药并破坏肠道菌群。\r\n长期服用质子泵抑制剂并非零风险，八周以上需评估感染、骨折及电解质紊乱风险，必要时改用H2受体拮抗剂或按需服用。\r\n误以为中成药与西药无冲突，一些含马兜铃酸或炙甘草的复方制剂可致肾毒性或心律失常，使用前应核对成分避免重复用药。\r\n七、家庭药箱配置建议\n感冒发热场景：对乙酰氨基酚、布洛芬、等渗盐水喷鼻剂。\n胃肠不适：奥美拉唑、蒙脱石散、口服补液盐。\n轻伤处理：碘伏、创可贴、弹性绷带。\n过敏反应：西替利嗪或氯雷他定，如有呼吸困难需立即就医。\n慢性病管理：高血压患者常备缬沙坦或硝苯地平控释片及电子血压计；糖尿病患者常备二甲双胍、速效胰岛素和葡萄糖片以防低血糖。\r\n八、未来趋势与展望\n精准医学将利用药物基因组学指导个体化选药，例如根据CYP2C19基因型调整氯吡格雷剂量或更换替格瑞洛。长效制剂的发展使得GLP-1类似物可周注射一次，精神疾病长效针剂可半年给药一次，显著改善依从性。数字健康通过智能血糖仪与云端平台实时监测血糖，利用人工智能预测低血糖并推送提醒。复方制剂和固定剂量复方片（例如“单片双降”降压药、阿托伐他汀/依泽替米贝组合）简化了处方结构，提高了疗效与依从性。\r\n结语\n常用药物种类繁多、用途广泛，既能在专业医疗机构发挥救命作用，也能在家庭场景中提供第一时间的健康守护。掌握药理机制、适应证与不良反应，遵循个体化与循证医学原则，是每一名医护人员与公众用药安全的核心。希望本文能帮助读者建立系统、科学的用药知识框架，在日常健康管理与疾病治疗中作出更安全、更有效的选择。', 'null', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, 1, 0, NULL, NULL, '2026-05-14 11:53:40', NULL, NULL, '2026-05-14 11:53:40', NULL);
INSERT INTO `kmc_document_segment` VALUES (228, 1001, '常见疾病：守护健康的 “必修课”.docx', 12, '68f1462f-7d45-4db1-9e6a-9e16c2f86137', 1, NULL, '常见疾病，是指在人群中发病率高、大众认知度广的一类疾病，既包括感冒、腹泻这类急性小病，也涵盖高血压、糖尿病等慢性疾病。它们的发生，往往与生活习惯、环境因素和遗传背景密切相关。了解常见疾病的基础常识，比如发病诱因、早期信号和预防要点，能帮助我们在日常生活中及时识别风险、科学应对，避免小病拖成大问题。比如，普通感冒多由病毒引起，以对症护理为主，无需滥用抗生素；而高血压则需要长期管理，通过饮食、运动和药物控制，才能有效降低心脑血管并发症的风险。掌握这些知识，是我们守护自身和家人健康的第一道防线。', '常见疾病，是指在人群中发病率高、大众认知度广的一类疾病，既包括感冒、腹泻这类急性小病，也涵盖高血压、糖尿病等慢性疾病。它们的发生，往往与生活习惯、环境因素和遗传背景密切相关。了解常见疾病的基础常识，比如发病诱因、早期信号和预防要点，能帮助我们在日常生活中及时识别风险、科学应对，避免小病拖成大问题。比如，普通感冒多由病毒引起，以对症护理为主，无需滥用抗生素；而高血压则需要长期管理，通过饮食、运动和药物控制，才能有效降低心脑血管并发症的风险。掌握这些知识，是我们守护自身和家人健康的第一道防线。', 'null', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, 1, 0, NULL, NULL, '2026-05-15 15:15:00', NULL, NULL, '2026-05-15 15:15:00', NULL);
INSERT INTO `kmc_document_segment` VALUES (229, 1001, '影像检查：医生的“透视眼”，读懂身体内部的秘密.pdf', 13, '316437e8-b6ef-45a9-9aa7-c91ec58fd942', 1, NULL, '影像检查，是通过医学影像设备，让医生 “看见” 身体内部结构和病变的重要\r\n手段，常见的包括 X 线、CT、超声、磁共振（MRI）等。它们就像医生的 “透视\r\n眼”，能清晰显示骨骼、器官、软组织的形态和结构，帮助发现肉眼无法观察到\r\n的病变。比如，X 线常用于检查骨折和肺部疾病，CT 能更清晰地显示胸部、腹部\r\n的病变细节，超声则对腹部脏器、心血管和胎儿检查安全无创，MRI 则擅长显示\r\n软组织病变，如脑部、脊髓和关节疾病。不同的影像检查各有优势和适用场景，\r\n医生会根据病情选择合适的检查方式，为诊断提供精准的依据。', '影像检查，是通过医学影像设备，让医生 “看见” 身体内部结构和病变的重要\r\n手段，常见的包括 X 线、CT、超声、磁共振（MRI）等。它们就像医生的 “透视\r\n眼”，能清晰显示骨骼、器官、软组织的形态和结构，帮助发现肉眼无法观察到\r\n的病变。比如，X 线常用于检查骨折和肺部疾病，CT 能更清晰地显示胸部、腹部\r\n的病变细节，超声则对腹部脏器、心血管和胎儿检查安全无创，MRI 则擅长显示\r\n软组织病变，如脑部、脊髓和关节疾病。不同的影像检查各有优势和适用场景，\r\n医生会根据病情选择合适的检查方式，为诊断提供精准的依据。', 'null', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, 1, 0, NULL, NULL, '2026-05-15 15:25:00', NULL, NULL, '2026-05-15 15:25:00', NULL);
INSERT INTO `kmc_document_segment` VALUES (230, 1001, '心血管介入治疗器械.txt', 11, '6b9a47ca-6d62-406a-a5f6-639ad1a42a06', 1, NULL, '心血管介入治疗器械：从导管到支架的全链条技术解析\r\n心血管介入治疗是现代心脏病学的核心技术之一，其成功的关键在于精密的器械。这些器械不仅是手术的工具，更是材料科学与生物医学工程的结晶。本文将深入探讨介入治疗中核心器械的技术原理与材料选择。\r\n一、导管系统：介入治疗的“导航车”\r\n技术原理：导管是介入治疗的“通道”，负责将各种器械和药物精准送达心脏或血管的病变部位\r\n。其核心技术在于“超滑”涂层和“可控塑形”。\r\n超滑涂层：导管表面通常涂有聚四氟乙烯（PTFE）等材料，极大地降低了与血管壁的摩擦力，使得导管能够轻松通过狭窄或迂曲的血管。\r\n可控塑形：导管的远端（前端）可以被塑造成特定的弯度，以适应不同解剖结构的需求。这种塑形通常是通过内部的金属丝（称为“J形导丝”）来实现的。\r\n材料科学：导管的主体材料多为高分子聚合物，如聚氨酯或聚乙烯，这些材料兼具柔韧性和足够的支撑力。\r\n二、球囊扩张导管：撑开血管的“微型气球”\r\n技术原理：球囊导管是经皮冠状动脉介入治疗（PCI）中最基础的器械之一\r\n。其原理是将一个折叠在导管尖端的微型球囊送至血管狭窄处，然后注入液体将其膨胀，从而撑开狭窄的血管，恢复血流。\r\n材料科学：球囊材料经历了从早期的天然乳胶到现在的高分子材料（如聚酰胺、聚乙烯等）的演变。现代球囊要求具备高爆破压力（以确保安全）、良好的顺应性（即扩张时能均匀受力）以及快速充盈和排空的能力。\r\n三、冠状动脉支架：血管的“永久性骨架”\r\n技术原理：支架是介入治疗中最关键的器械，它的作用是在球囊扩张后，为血管提供一个永久的支撑，防止血管回缩或再狭窄\r\n。\r\n材料科学：支架材料的选择是其技术发展的核心。\r\n第一代支架：主要为不锈钢支架，优点是强度高，但缺点是永久存留体内，可能引起晚期血栓或限制血管的自然舒缩。\r\n第二代支架：为可降解支架，如聚乳酸（PLA）支架。其最大的特点是可在植入后数月到数年内逐渐降解并被人体吸收，最终血管可以恢复自然状态。\r\n第三代支架：为药物洗脱支架（DES），在金属支架表面涂有可缓慢释放的抗增殖药物（如雷帕霉素）。这种支架既能提供永久支撑，又能抑制血管内膜的过度增生，从而显著降低再狭窄率。\r\n四、辅助器械：介入治疗的“得力助手”\r\n导丝：导丝是介入治疗的“先锋”，负责在血管内开辟通路，引导其他器械到达目的地。现代导丝的尖端非常柔软，可以安全地通过极其复杂的病变，而其尾部则非常坚硬，以保证操作者能够精确地控制其走向。\r\n造影剂：造影剂是介入治疗的“眼睛”。通过向血管内注射含碘的造影剂，可以使血管在X线', '心血管介入治疗器械：从导管到支架的全链条技术解析\r\n心血管介入治疗是现代心脏病学的核心技术之一，其成功的关键在于精密的器械。这些器械不仅是手术的工具，更是材料科学与生物医学工程的结晶。本文将深入探讨介入治疗中核心器械的技术原理与材料选择。\r\n一、导管系统：介入治疗的“导航车”\r\n技术原理：导管是介入治疗的“通道”，负责将各种器械和药物精准送达心脏或血管的病变部位\r\n。其核心技术在于“超滑”涂层和“可控塑形”。\r\n超滑涂层：导管表面通常涂有聚四氟乙烯（PTFE）等材料，极大地降低了与血管壁的摩擦力，使得导管能够轻松通过狭窄或迂曲的血管。\r\n可控塑形：导管的远端（前端）可以被塑造成特定的弯度，以适应不同解剖结构的需求。这种塑形通常是通过内部的金属丝（称为“J形导丝”）来实现的。\r\n材料科学：导管的主体材料多为高分子聚合物，如聚氨酯或聚乙烯，这些材料兼具柔韧性和足够的支撑力。\r\n二、球囊扩张导管：撑开血管的“微型气球”\r\n技术原理：球囊导管是经皮冠状动脉介入治疗（PCI）中最基础的器械之一\r\n。其原理是将一个折叠在导管尖端的微型球囊送至血管狭窄处，然后注入液体将其膨胀，从而撑开狭窄的血管，恢复血流。\r\n材料科学：球囊材料经历了从早期的天然乳胶到现在的高分子材料（如聚酰胺、聚乙烯等）的演变。现代球囊要求具备高爆破压力（以确保安全）、良好的顺应性（即扩张时能均匀受力）以及快速充盈和排空的能力。\r\n三、冠状动脉支架：血管的“永久性骨架”\r\n技术原理：支架是介入治疗中最关键的器械，它的作用是在球囊扩张后，为血管提供一个永久的支撑，防止血管回缩或再狭窄\r\n。\r\n材料科学：支架材料的选择是其技术发展的核心。\r\n第一代支架：主要为不锈钢支架，优点是强度高，但缺点是永久存留体内，可能引起晚期血栓或限制血管的自然舒缩。\r\n第二代支架：为可降解支架，如聚乳酸（PLA）支架。其最大的特点是可在植入后数月到数年内逐渐降解并被人体吸收，最终血管可以恢复自然状态。\r\n第三代支架：为药物洗脱支架（DES），在金属支架表面涂有可缓慢释放的抗增殖药物（如雷帕霉素）。这种支架既能提供永久支撑，又能抑制血管内膜的过度增生，从而显著降低再狭窄率。\r\n四、辅助器械：介入治疗的“得力助手”\r\n导丝：导丝是介入治疗的“先锋”，负责在血管内开辟通路，引导其他器械到达目的地。现代导丝的尖端非常柔软，可以安全地通过极其复杂的病变，而其尾部则非常坚硬，以保证操作者能够精确地控制其走向。\r\n造影剂：造影剂是介入治疗的“眼睛”。通过向血管内注射含碘的造影剂，可以使血管在X线', 'null', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, 1, 0, NULL, NULL, '2026-05-15 15:40:00', NULL, NULL, '2026-05-15 15:40:00', NULL);
INSERT INTO `kmc_document_segment` VALUES (231, 1001, '心血管介入治疗器械.txt', 11, '65e5a606-52e0-4236-b6e7-80ebbeeb6217', 2, NULL, '的地。现代导丝的尖端非常柔软，可以安全地通过极其复杂的病变，而其尾部则非常坚硬，以保证操作者能够精确地控制其走向。\r\n造影剂：造影剂是介入治疗的“眼睛”。通过向血管内注射含碘的造影剂，可以使血管在X线下显影，从而让医生清晰地看到血管的形态、狭窄的位置和程度。', '的地。现代导丝的尖端非常柔软，可以安全地通过极其复杂的病变，而其尾部则非常坚硬，以保证操作者能够精确地控制其走向。\r\n造影剂：造影剂是介入治疗的“眼睛”。通过向血管内注射含碘的造影剂，可以使血管在X线下显影，从而让医生清晰地看到血管的形态、狭窄的位置和程度。', 'null', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, 1, 0, NULL, NULL, '2026-05-15 15:40:00', NULL, NULL, '2026-05-15 15:40:00', NULL);
INSERT INTO `kmc_document_segment` VALUES (232, 1001, '典型症状：读懂身体发出的 “求救信号”.docx', 14, '29c7b464-4c60-42e9-bc26-111555aa5188', 1, NULL, '症状，是身体向我们发出的最直接的信号，而典型症状，就是某种疾病最具代表性、最容易识别的表现。比如，肺炎常伴随发热、咳嗽、咳痰，心梗可能表现为胸痛、胸闷、肩背放射痛。认识典型症状，不是让我们自行诊断，而是帮助我们提高警惕，及时就医。很多疾病的早期症状并不典型，但抓住核心信号，就能为治疗争取宝贵时间。比如不明原因的持续消瘦、反复低热，可能是某些严重疾病的预警，绝不能忽视。读懂这些 “信号”，才能在健康问题出现时，既不盲目恐慌，也不麻痹大意，做出科学的应对选择。', '症状，是身体向我们发出的最直接的信号，而典型症状，就是某种疾病最具代表性、最容易识别的表现。比如，肺炎常伴随发热、咳嗽、咳痰，心梗可能表现为胸痛、胸闷、肩背放射痛。认识典型症状，不是让我们自行诊断，而是帮助我们提高警惕，及时就医。很多疾病的早期症状并不典型，但抓住核心信号，就能为治疗争取宝贵时间。比如不明原因的持续消瘦、反复低热，可能是某些严重疾病的预警，绝不能忽视。读懂这些 “信号”，才能在健康问题出现时，既不盲目恐慌，也不麻痹大意，做出科学的应对选择。', 'null', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, 1, 0, NULL, NULL, '2026-05-15 15:50:00', NULL, NULL, '2026-05-15 15:50:00', NULL);
INSERT INTO `kmc_document_segment` VALUES (233, 1001, '治疗方案：科学应对疾病的 “路线图”.docx', 15, 'e19871b1-b80f-4832-9612-248914c33054', 1, NULL, '治疗方案，是医生根据患者的病情、身体状况和疾病特点，制定的一套个性化诊疗计划，涵盖了药物治疗、手术治疗、物理治疗、康复护理等多个方面。它不是一成不变的模板，而是结合循证医学证据和患者个体情况制定的 “专属路线图”。比如，高血压的治疗方案，会根据患者的血压水平、合并症，制定饮食、运动和药物的综合管理计划；而肿瘤的治疗，则可能需要手术、化疗、放疗等多学科联合的方案。了解治疗方案的核心逻辑，能帮助患者更好地配合治疗，理解不同治疗手段的目的和意义，减少焦虑，提高治疗依从性，共同对抗疾病。', '治疗方案，是医生根据患者的病情、身体状况和疾病特点，制定的一套个性化诊疗计划，涵盖了药物治疗、手术治疗、物理治疗、康复护理等多个方面。它不是一成不变的模板，而是结合循证医学证据和患者个体情况制定的 “专属路线图”。比如，高血压的治疗方案，会根据患者的血压水平、合并症，制定饮食、运动和药物的综合管理计划；而肿瘤的治疗，则可能需要手术、化疗、放疗等多学科联合的方案。了解治疗方案的核心逻辑，能帮助患者更好地配合治疗，理解不同治疗手段的目的和意义，减少焦虑，提高治疗依从性，共同对抗疾病。', 'null', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, 1, 0, NULL, NULL, '2026-05-15 15:55:00', NULL, NULL, '2026-05-15 15:55:00', NULL);
INSERT INTO `kmc_document_segment` VALUES (234, 1001, '医学科普知识.xlsx', 16, '4541a52c-fa91-4d4b-bd31-9b4ef0c12c5c', 1, NULL, '医学科普知识库\n	序号	分类名称	简短描述	完整科普文章\n	1	常见疾病	人群中发病率较高的常见病种知识，含病因、高危因素与预防要点。	常见疾病，是指在人群中发病率高、大众认知度广的一类疾病，既包括感冒、腹泻这类急性小病，也涵盖高血压、糖尿病等慢性疾病。它们的发生，往往与生活习惯、环境因素和遗传背景密切相关。了解常见疾病的基础常识，比如发病诱因、早期信号和预防要点，能帮助我们在日常生活中及时识别风险、科学应对，避免小病拖成大问题。比如，普通感冒多由病毒引起，以对症护理为主，无需滥用抗生素；而高血压则需要长期管理，通过饮食、运动和药物控制，才能有效降低心脑血管并发症的风险。掌握这些知识，是我们守护自身和家人健康的第一道防线。\n	2	典型症状	各类疾病的代表性临床表现，帮助快速识别身体异常信号。	症状，是身体向我们发出的最直接的信号，而典型症状，就是某种疾病最具代表性、最容易识别的表现。比如，肺炎常伴随发热、咳嗽、咳痰，心梗可能表现为胸痛、胸闷、肩背放射痛。认识典型症状，不是让我们自行诊断，而是帮助我们提高警惕，及时就医。很多疾病的早期症状并不典型，但抓住核心信号，就能为治疗争取宝贵时间。比如不明原因的持续消瘦、反复低热，可能是某些严重疾病的预警，绝不能忽视。读懂这些“信号”，才能在健康问题出现时，既不盲目恐慌，也不麻痹大意，做出科学的应对选择。\n	3	常用药物	临床常见药物的基础信息，含适应症、用法用量与安全用药提示。	常用药物，是我们日常应对疾病、缓解不适的重要工具，小到感冒药、退烧药，大到慢性病的长期用药，都属于这个范畴。但药物是把“双刃剑”，合理使用能治病，滥用则可能带来副作用甚至健康风险。了解常用药物的基本常识，比如适应症、用法用量、禁忌和注意事项，是安全用药的前提。比如，退烧药不可过量服用，避免损伤肝脏；抗生素仅对细菌感染有效，对病毒感染的感冒无效，滥用还会导致耐药性。同时，也要注意药物的有效期、储存条件，以及不同药物之间的相互作用，遵医嘱或按说明书用药，才能让药物真正发挥治病救人的作用。\n	4	治疗方案	不同疾病的主流诊疗思路与干预手段，含药物、手术及康复管理。	治疗方案，是医生根据患者的病情、身体状况和疾病特点，制定的一套个性化诊疗计划，涵盖了药物治疗、手术治疗、物理治疗、康复护理等多个方面。它不是一成不变的模板，而是结合循证医学证据和患者个体情况制定的“专属路线图”。比如，高血压的治疗方案，会根据患者的血压水平、合并症，制定饮食、运动和药物的综合管理计划；而肿瘤的治疗，则可能需要手术、化疗、放疗等', '医学科普知识库\n	序号	分类名称	简短描述	完整科普文章\n	1	常见疾病	人群中发病率较高的常见病种知识，含病因、高危因素与预防要点。	常见疾病，是指在人群中发病率高、大众认知度广的一类疾病，既包括感冒、腹泻这类急性小病，也涵盖高血压、糖尿病等慢性疾病。它们的发生，往往与生活习惯、环境因素和遗传背景密切相关。了解常见疾病的基础常识，比如发病诱因、早期信号和预防要点，能帮助我们在日常生活中及时识别风险、科学应对，避免小病拖成大问题。比如，普通感冒多由病毒引起，以对症护理为主，无需滥用抗生素；而高血压则需要长期管理，通过饮食、运动和药物控制，才能有效降低心脑血管并发症的风险。掌握这些知识，是我们守护自身和家人健康的第一道防线。\n	2	典型症状	各类疾病的代表性临床表现，帮助快速识别身体异常信号。	症状，是身体向我们发出的最直接的信号，而典型症状，就是某种疾病最具代表性、最容易识别的表现。比如，肺炎常伴随发热、咳嗽、咳痰，心梗可能表现为胸痛、胸闷、肩背放射痛。认识典型症状，不是让我们自行诊断，而是帮助我们提高警惕，及时就医。很多疾病的早期症状并不典型，但抓住核心信号，就能为治疗争取宝贵时间。比如不明原因的持续消瘦、反复低热，可能是某些严重疾病的预警，绝不能忽视。读懂这些“信号”，才能在健康问题出现时，既不盲目恐慌，也不麻痹大意，做出科学的应对选择。\n	3	常用药物	临床常见药物的基础信息，含适应症、用法用量与安全用药提示。	常用药物，是我们日常应对疾病、缓解不适的重要工具，小到感冒药、退烧药，大到慢性病的长期用药，都属于这个范畴。但药物是把“双刃剑”，合理使用能治病，滥用则可能带来副作用甚至健康风险。了解常用药物的基本常识，比如适应症、用法用量、禁忌和注意事项，是安全用药的前提。比如，退烧药不可过量服用，避免损伤肝脏；抗生素仅对细菌感染有效，对病毒感染的感冒无效，滥用还会导致耐药性。同时，也要注意药物的有效期、储存条件，以及不同药物之间的相互作用，遵医嘱或按说明书用药，才能让药物真正发挥治病救人的作用。\n	4	治疗方案	不同疾病的主流诊疗思路与干预手段，含药物、手术及康复管理。	治疗方案，是医生根据患者的病情、身体状况和疾病特点，制定的一套个性化诊疗计划，涵盖了药物治疗、手术治疗、物理治疗、康复护理等多个方面。它不是一成不变的模板，而是结合循证医学证据和患者个体情况制定的“专属路线图”。比如，高血压的治疗方案，会根据患者的血压水平、合并症，制定饮食、运动和药物的综合管理计划；而肿瘤的治疗，则可能需要手术、化疗、放疗等', 'null', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, 1, 0, NULL, NULL, '2026-05-15 16:10:00', NULL, NULL, '2026-05-15 16:10:00', NULL);
INSERT INTO `kmc_document_segment` VALUES (235, 1001, '医学科普知识.xlsx', 16, 'd193bf66-05fc-423d-a8de-a16bf2bc3d87', 2, NULL, '不变的模板，而是结合循证医学证据和患者个体情况制定的“专属路线图”。比如，高血压的治疗方案，会根据患者的血压水平、合并症，制定饮食、运动和药物的综合管理计划；而肿瘤的治疗，则可能需要手术、化疗、放疗等多学科联合的方案。了解治疗方案的核心逻辑，能帮助患者更好地配合治疗，理解不同治疗手段的目的和意义，减少焦虑，提高治疗依从性，共同对抗疾病。\n	5	影像检查	X线/CT/超声/MRI等影像学检查的原理、适用场景与报告解读要点。	影像检查，是通过医学影像设备，让医生“看见”身体内部结构和病变的重要手段，常见的包括X线、CT、超声、磁共振（MRI）等。它们就像医生的“透视眼”，能清晰显示骨骼、器官、软组织的形态和结构，帮助发现肉眼无法观察到的病变。比如，X线常用于检查骨折和肺部疾病，CT能更清晰地显示胸部、腹部的病变细节，超声则对腹部脏器、心血管和胎儿检查安全无创，MRI则擅长显示软组织病变，如脑部、脊髓和关节疾病。不同的影像检查各有优势和适用场景，医生会根据病情选择合适的检查方式，为诊断提供精准的依据。\n	6	实验室检查	血/尿/生化/病原学等检验项目的临床意义、参考值与异常提示。	实验室检查，是通过对血液、尿液、粪便、体液等样本进行检测，分析其中的成分和指标，来评估身体功能、诊断疾病的重要方法。血常规、尿常规、生化检查、病原体检测等，都属于实验室检查的范畴。这些指标就像身体状态的“晴雨表”，比如血常规中的白细胞升高，可能提示感染；血糖升高，是糖尿病的重要诊断依据；肝肾功能指标异常，则反映了对应器官的功能状态。实验室检查结果需要结合临床症状和其他检查综合解读，它不仅能帮助医生明确诊断，还能监测病情变化、评估治疗效果，是临床诊疗中不可或缺的一环。\n	7	器官系统	人体各大系统（呼吸/循环/消化等）的组成结构与核心功能概述。	人体由多个器官系统组成，每个系统都有明确的功能，又相互协作，共同维持生命活动的正常运转。比如，呼吸系统负责气体交换，为身体提供氧气、排出二氧化碳；循环系统通过心脏和血管，将血液输送到全身各处，运输营养和氧气；消化系统负责食物的消化和吸收，为身体提供能量；神经系统则像“指挥中心”，调控着所有器官和系统的活动。这些系统不是孤立存在的，比如运动时，呼吸系统、循环系统和肌肉系统会协同工作，满足身体的能量需求。了解器官系统的基本组成和功能，能帮助我们更好地理解身体的运作规律，也能更清晰地认识疾病对身体的影响。\n	8	生理功能	人体正常生命活动的调节机制，如代谢、免疫、体温调节等基础原理。	生理功能，是指人体器官和系统所执行的正常生命活动，比如呼吸、心跳、消化、代谢、免疫、体温调节等，是维持生命的基础。每一项生', '不变的模板，而是结合循证医学证据和患者个体情况制定的“专属路线图”。比如，高血压的治疗方案，会根据患者的血压水平、合并症，制定饮食、运动和药物的综合管理计划；而肿瘤的治疗，则可能需要手术、化疗、放疗等多学科联合的方案。了解治疗方案的核心逻辑，能帮助患者更好地配合治疗，理解不同治疗手段的目的和意义，减少焦虑，提高治疗依从性，共同对抗疾病。\n	5	影像检查	X线/CT/超声/MRI等影像学检查的原理、适用场景与报告解读要点。	影像检查，是通过医学影像设备，让医生“看见”身体内部结构和病变的重要手段，常见的包括X线、CT、超声、磁共振（MRI）等。它们就像医生的“透视眼”，能清晰显示骨骼、器官、软组织的形态和结构，帮助发现肉眼无法观察到的病变。比如，X线常用于检查骨折和肺部疾病，CT能更清晰地显示胸部、腹部的病变细节，超声则对腹部脏器、心血管和胎儿检查安全无创，MRI则擅长显示软组织病变，如脑部、脊髓和关节疾病。不同的影像检查各有优势和适用场景，医生会根据病情选择合适的检查方式，为诊断提供精准的依据。\n	6	实验室检查	血/尿/生化/病原学等检验项目的临床意义、参考值与异常提示。	实验室检查，是通过对血液、尿液、粪便、体液等样本进行检测，分析其中的成分和指标，来评估身体功能、诊断疾病的重要方法。血常规、尿常规、生化检查、病原体检测等，都属于实验室检查的范畴。这些指标就像身体状态的“晴雨表”，比如血常规中的白细胞升高，可能提示感染；血糖升高，是糖尿病的重要诊断依据；肝肾功能指标异常，则反映了对应器官的功能状态。实验室检查结果需要结合临床症状和其他检查综合解读，它不仅能帮助医生明确诊断，还能监测病情变化、评估治疗效果，是临床诊疗中不可或缺的一环。\n	7	器官系统	人体各大系统（呼吸/循环/消化等）的组成结构与核心功能概述。	人体由多个器官系统组成，每个系统都有明确的功能，又相互协作，共同维持生命活动的正常运转。比如，呼吸系统负责气体交换，为身体提供氧气、排出二氧化碳；循环系统通过心脏和血管，将血液输送到全身各处，运输营养和氧气；消化系统负责食物的消化和吸收，为身体提供能量；神经系统则像“指挥中心”，调控着所有器官和系统的活动。这些系统不是孤立存在的，比如运动时，呼吸系统、循环系统和肌肉系统会协同工作，满足身体的能量需求。了解器官系统的基本组成和功能，能帮助我们更好地理解身体的运作规律，也能更清晰地认识疾病对身体的影响。\n	8	生理功能	人体正常生命活动的调节机制，如代谢、免疫、体温调节等基础原理。	生理功能，是指人体器官和系统所执行的正常生命活动，比如呼吸、心跳、消化、代谢、免疫、体温调节等，是维持生命的基础。每一项生', 'null', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, 1, 0, NULL, NULL, '2026-05-15 16:10:00', NULL, NULL, '2026-05-15 16:10:00', NULL);
INSERT INTO `kmc_document_segment` VALUES (236, 1001, '医学科普知识.xlsx', 16, '14ee9d00-3b84-43ea-a288-f48c1bc12c18', 3, NULL, '8	生理功能	人体正常生命活动的调节机制，如代谢、免疫、体温调节等基础原理。	生理功能，是指人体器官和系统所执行的正常生命活动，比如呼吸、心跳、消化、代谢、免疫、体温调节等，是维持生命的基础。每一项生理功能都有其精密的调节机制，比如体温调节，会通过出汗、血管收缩等方式，将体温维持在37℃左右；血糖调节则通过胰岛素和胰高血糖素的相互作用，保持血糖的稳定。当生理功能出现异常时，就会引发疾病，比如代谢异常会导致糖尿病、肥胖，免疫功能低下则容易发生感染。了解生理功能的正常状态和调节机制，能帮助我们更好地理解疾病的发生原理，也能通过合理的生活方式，维持生理功能的稳定，守护身体健康。', '8	生理功能	人体正常生命活动的调节机制，如代谢、免疫、体温调节等基础原理。	生理功能，是指人体器官和系统所执行的正常生命活动，比如呼吸、心跳、消化、代谢、免疫、体温调节等，是维持生命的基础。每一项生理功能都有其精密的调节机制，比如体温调节，会通过出汗、血管收缩等方式，将体温维持在37℃左右；血糖调节则通过胰岛素和胰高血糖素的相互作用，保持血糖的稳定。当生理功能出现异常时，就会引发疾病，比如代谢异常会导致糖尿病、肥胖，免疫功能低下则容易发生感染。了解生理功能的正常状态和调节机制，能帮助我们更好地理解疾病的发生原理，也能通过合理的生活方式，维持生理功能的稳定，守护身体健康。', 'null', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, 1, 0, NULL, NULL, '2026-05-15 16:10:00', NULL, NULL, '2026-05-15 16:10:00', NULL);
INSERT INTO `kmc_document_segment` VALUES (237, 1001, '常用药物：安全用药，守护健康.docx', 17, 'ae1ed595-5c3a-475d-a9cb-bec92098006f', 1, NULL, '常用药物，是我们日常应对疾病、缓解不适的重要工具。小到感冒时服用的退烧药、鼻塞时使用的滴鼻剂，大到高血压、糖尿病患者需要长期服用的降压药、降糖药，都属于常用药物的范畴。它们的存在，让我们在面对常见健康问题时，有了可及的应对手段，也为慢性病患者维持病情稳定、保障生活质量提供了关键支撑。\n但我们必须清醒地认识到，药物是一把 “双刃剑”。合理使用时，它能精准缓解症状、控制病情，甚至挽救生命；可一旦滥用、错用，不仅无法达到治疗效果，还可能带来恶心、呕吐、肝肾损伤等副作用，严重时甚至会危及生命。因此，了解常用药物的基本常识，是安全用药的第一步，也是最关键的一步。\n了解常用药物，首先要明确其适应症，也就是它能治疗什么问题。比如，布洛芬既能退烧，也能缓解头痛、关节痛等轻中度疼痛；而抗生素类药物，仅对细菌感染引起的炎症有效，对病毒导致的普通感冒、流感则毫无作用，盲目服用反而会破坏体内正常菌群，甚至诱导细菌产生耐药性，让后续真正需要时药物失效。\n其次，用法用量是安全用药的核心细节。无论是口服药的服用时间（饭前、饭后还是随餐）、服用频率，还是外用药物的涂抹范围、使用次数，都需要严格遵循医嘱或药品说明书的要求。比如退烧药，两次服用的间隔通常不能少于 4-6 小时，24 小时内服用次数也有明确限制，过量服用会加重肝脏代谢负担，造成不可逆的损伤。\n除此之外，药物的禁忌和注意事项也绝不能忽视。比如，对青霉素过敏的人严禁使用青霉素类抗生素；孕妇、哺乳期女性、肝肾功能不全者，在使用任何药物前都需要咨询医生，避免药物对自身或胎儿、婴儿造成不良影响。同时，不同药物之间可能存在相互作用，比如某些感冒药中含有相同成分，同时服用可能导致成分过量，引发风险。\n最后，药物的有效期和储存条件也需要格外留意。过期药物的药效会下降，甚至可能分解产生有害物质；而部分药物需要避光、冷藏保存，不当储存会导致药物提前失效。用药前检查有效期、按要求储存药物，是避免无效用药和安全隐患的基础操作。\n遵医嘱用药、按说明书用药，不是一句口号，而是对自己健康负责的态度。只有真正了解常用药物的特点，科学、规范地使用它们，才能让药物发挥应有的治疗作用，真正成为守护我们健康的可靠帮手。', '常用药物，是我们日常应对疾病、缓解不适的重要工具。小到感冒时服用的退烧药、鼻塞时使用的滴鼻剂，大到高血压、糖尿病患者需要长期服用的降压药、降糖药，都属于常用药物的范畴。它们的存在，让我们在面对常见健康问题时，有了可及的应对手段，也为慢性病患者维持病情稳定、保障生活质量提供了关键支撑。\n但我们必须清醒地认识到，药物是一把 “双刃剑”。合理使用时，它能精准缓解症状、控制病情，甚至挽救生命；可一旦滥用、错用，不仅无法达到治疗效果，还可能带来恶心、呕吐、肝肾损伤等副作用，严重时甚至会危及生命。因此，了解常用药物的基本常识，是安全用药的第一步，也是最关键的一步。\n了解常用药物，首先要明确其适应症，也就是它能治疗什么问题。比如，布洛芬既能退烧，也能缓解头痛、关节痛等轻中度疼痛；而抗生素类药物，仅对细菌感染引起的炎症有效，对病毒导致的普通感冒、流感则毫无作用，盲目服用反而会破坏体内正常菌群，甚至诱导细菌产生耐药性，让后续真正需要时药物失效。\n其次，用法用量是安全用药的核心细节。无论是口服药的服用时间（饭前、饭后还是随餐）、服用频率，还是外用药物的涂抹范围、使用次数，都需要严格遵循医嘱或药品说明书的要求。比如退烧药，两次服用的间隔通常不能少于 4-6 小时，24 小时内服用次数也有明确限制，过量服用会加重肝脏代谢负担，造成不可逆的损伤。\n除此之外，药物的禁忌和注意事项也绝不能忽视。比如，对青霉素过敏的人严禁使用青霉素类抗生素；孕妇、哺乳期女性、肝肾功能不全者，在使用任何药物前都需要咨询医生，避免药物对自身或胎儿、婴儿造成不良影响。同时，不同药物之间可能存在相互作用，比如某些感冒药中含有相同成分，同时服用可能导致成分过量，引发风险。\n最后，药物的有效期和储存条件也需要格外留意。过期药物的药效会下降，甚至可能分解产生有害物质；而部分药物需要避光、冷藏保存，不当储存会导致药物提前失效。用药前检查有效期、按要求储存药物，是避免无效用药和安全隐患的基础操作。\n遵医嘱用药、按说明书用药，不是一句口号，而是对自己健康负责的态度。只有真正了解常用药物的特点，科学、规范地使用它们，才能让药物发挥应有的治疗作用，真正成为守护我们健康的可靠帮手。', 'null', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, 1, 0, NULL, NULL, '2026-05-15 16:10:03', NULL, NULL, '2026-05-15 16:10:03', NULL);
INSERT INTO `kmc_knowledge_base` VALUES (1, 1001, '75f94f43-9c90-4c6d-b48e-7290403322e0', '基础医学知识库', '面向医疗从业者和健康爱好者的综合性基础医学知识库，涵盖疾病、药物、检查、解剖生理及健康管理等多个领域，旨在提供系统化、结构化的医学知识支持。', '/2025/11/18/691bd5b7e4b008a3de0b1740.png', '[{\"name\":\"疾病\"},{\"name\":\"药品\"}]', 'high_quality', NULL, 'text-embedding-v4', '1', 'hybrid_search', 1, '1', 'gte-rerank', 3, 0, 0.0, 'reranking_model', 0.5, 0.5, 1, 0, '吴同', 2, '2026-04-24 10:01:44', '小桐', 1, '2026-05-14 13:37:55', NULL);
INSERT INTO `kmc_knowledge_base` VALUES (2, 1001, 'b7741c6f-88a1-42a7-81a7-79a05ff212cc', '水利工程设计标准知识库', '汇集国家和行业设计规范（如《水工建筑物设计规范》）、典型设计方案、结构参数与安全系数，支持工程设计智能辅助与合规校验。', '/2025/11/18/691bd5a3e4b008a3de0b173f.png', '[{\"name\":\"水利工程\"}]', 'high_quality', NULL, 'text-embedding-v4', '5', 'hybrid_search', 1, '1', 'gte-rerank-v2', 3, 0, 0.0, 'reranking_model', 0.5, 0.5, 1, 0, '吴同', 2, '2026-04-24 10:01:44', '吴同', NULL, '2026-04-24 10:01:44', NULL);
INSERT INTO `kmc_knowledge_base` VALUES (3, 1001, '71dbae3b-2186-4755-95c4-6f9c622d13c9', '水利历史灾害案例知识库', '收录历年洪涝、干旱、溃坝、滑坡等灾害的时间、地点、成因、损失、应对措施与教训，用于灾害模式分析与应急培训。', '/2025/11/18/691bd5c9e4b008a3de0b1741.png', '[{\"name\":\"水利灾害\"}]', 'high_quality', NULL, 'text-embedding-v4', '5', 'hybrid_search', 1, '1', 'gte-rerank-v2', 3, 0, 0.0, 'reranking_model', 0.5, 0.5, 0, 0, '吴同', 2, '2026-04-24 10:01:44', '吴同', NULL, '2026-04-24 10:01:44', NULL);
