-- ----------------------------
-- Table structure for ai_workflow_node
-- ----------------------------
DROP TABLE IF EXISTS `ai_workflow_node`;
CREATE TABLE `ai_workflow_node`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `workspace_id` bigint(20) NOT NULL COMMENT '工作区id',
  `workflow_id` bigint(20) NOT NULL COMMENT '工作流id',
  `node_name` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '节点名称',
  `model_id` bigint(20) NULL DEFAULT NULL COMMENT '模型id',
  `model_name` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '模型名称',
  `temperature` decimal(10, 1) NULL DEFAULT NULL COMMENT '温度;控制生成结果的多样性和随机性。数值越小，越严谨；数值越大，越发散。',
  `max_tokens` int(11) NULL DEFAULT NULL COMMENT '最大标记;指定生成结果长度的上限。如果生成结果截断，可以调大该参数。',
  `top_p` decimal(10, 2) NULL DEFAULT NULL COMMENT 'TopP;控制生成结果的随机性。数值越小，随机性越弱；数值越大，随机性越强。一般而言，top_p 和 temperature 两个参数选择一个进行调整即可。',
  `logprobs` tinyint(1) NULL DEFAULT NULL COMMENT 'Logprobs;是否返回所输出 token 的对数概率。如果为 true，则在 message 的 content 中返回每个输出 token 的对数概率。',
  `top_logprobs` int(11) NULL DEFAULT NULL COMMENT 'Top Logprobs;一个介于 0 到 20 之间的整数 N，指定每个输出位置返回输出概率 top N 的 token，且返回这些 token 的对数概率。指定此参数时，logprobs 必须为 true。',
  `frequency_penalty` decimal(10, 1) NULL DEFAULT NULL COMMENT '频率惩罚;介于 -2.0 和 2.0 之间的数字。如果该值为正，那么新 token 会根据其在已有文本中的出现频率受到相应的惩罚，降低模型重复相同内容的可能性。',
  `response_format` tinyint(4) UNSIGNED NULL DEFAULT NULL COMMENT '回复格式;指定模型必须输出的格式',
  `stop_sequence` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '停止序列;最多四个序列，API 将停止生成更多的 token。返回的文本将不包含停止序列。',
  `valid_flag` tinyint(1) NOT NULL DEFAULT 1 COMMENT '是否有效;0：无效，1：有效',
  `del_flag` tinyint(1) NOT NULL DEFAULT 0 COMMENT '删除标志;1：已删除，0：未删除',
  `create_by` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '创建人',
  `creator_id` bigint(20) NULL DEFAULT NULL COMMENT '创建人id',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '更新人',
  `updater_id` bigint(20) NULL DEFAULT NULL COMMENT '更新人id',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '更新时间',
  `remark` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '备注',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 23 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '节点管理' ROW_FORMAT = DYNAMIC;

